const PART5_EASY2 = [
  {id:"p5e2_1",question:"The office _____ at 8:30 every weekday morning.",options:["A) open","B) opens","C) opened","D) opening"],answer:"B",explanation:"'Opens' is correct because the third-person singular subject 'the office' requires the -s form of the verb in the present simple tense, which is used for regular, repeated routines. 'Open' is wrong because it is the base form, used for I/you/we/they but not for a singular third-person subject. 'Opened' is wrong because it is the simple past tense, which describes a completed past event rather than a current daily habit. 'Opening' is wrong because it is a present participle and cannot stand alone as the main verb without an auxiliary such as 'is'.",category:"Grammar"},
  {id:"p5e2_2",question:"She _____ her laptop at home and had to borrow one.",options:["A) forgets","B) forgot","C) has forgotten","D) forgetting"],answer:"B",explanation:"'Forgot' is correct because the simple past tense is used for a specific completed action that happened at a definite point in the past, as shown by the consequence 'had to borrow one.' 'Forgets' is wrong because it is the present simple, which describes current habits rather than a past event. 'Has forgotten' is wrong because the present perfect describes an action with a connection to the present, but the sentence describes a finished past situation. 'Forgetting' is wrong because it is a present participle and cannot function as the main verb without an auxiliary.",category:"Grammar"},
  {id:"p5e2_3",question:"The shipment _____ arrive by Thursday at the latest.",options:["A) shall","B) will","C) must","D) could"],answer:"B",explanation:"'Will arrive' is correct because 'will' expresses a future expectation or prediction about a scheduled event, which fits the context of an expected delivery. 'Shall' is wrong because in modern business English it is largely restricted to formal offers or legal language (e.g., 'shall be governed by'), not general future predictions. 'Must' is wrong because it expresses obligation or logical deduction rather than a straightforward future expectation. 'Could' is wrong because it expresses possibility or ability, implying uncertainty, whereas the sentence states a firm expectation.",category:"Modal"},
  {id:"p5e2_4",question:"We _____ a new supplier after the previous one missed three deadlines.",options:["A) find","B) have found","C) found","D) are finding"],answer:"C",explanation:"'Found' is correct because the simple past tense describes a completed action that occurred at a specific point in the past, here triggered by the previous supplier's failures. 'Find' is wrong because it is the present simple, which expresses current habits or general truths rather than a finished past event. 'Have found' is wrong because the present perfect is used for past actions with current relevance, but the context implies this is a concluded past story. 'Are finding' is wrong because the present continuous describes an action happening right now, not a completed past decision.",category:"Grammar"},
  {id:"p5e2_5",question:"He introduced _____ to the new client at the networking event.",options:["A) him","B) himself","C) his","D) he"],answer:"B",explanation:"'Himself' is correct because when the subject ('he') and the object of the verb refer to the same person, a reflexive pronoun is required ('introduced himself'). 'Him' is wrong because it is an object pronoun referring to a different person, so using it would mean he introduced someone else to the client. 'His' is wrong because it is a possessive adjective that must precede a noun (e.g., 'his colleague'), and cannot serve as the object of the verb. 'He' is wrong because it is a subject pronoun and cannot function as the object of the verb 'introduced'.",category:"Grammar"},
  {id:"p5e2_6",question:"The team managed the entire project _____ with no outside help.",options:["A) themselves","B) itself","C) yourself","D) herself"],answer:"A",explanation:"'Themselves' is correct because the subject 'the team' is treated as a group of people (plural), so the reflexive pronoun must be third-person plural to match. 'Itself' is wrong because it is the third-person singular neuter reflexive, used for objects or animals, not for a group of people. 'Yourself' is wrong because it is the second-person singular reflexive, which refers to 'you' and does not match the subject 'the team'. 'Herself' is wrong because it is the third-person singular feminine reflexive, which would only be correct if the subject were a single woman.",category:"Grammar"},
  {id:"p5e2_7",question:"Please help _____ to the refreshments after the presentation.",options:["A) you","B) yours","C) yourself","D) your"],answer:"C",explanation:"'Yourself' is correct because 'help yourself to' is a fixed English expression meaning 'take freely,' and it requires the reflexive pronoun matching the subject ('you'). 'You' is wrong because it is the standard object pronoun and 'help you to' would imply someone else is helping you, not that you are serving yourself. 'Yours' is wrong because it is a possessive pronoun used to indicate ownership (e.g., 'this is yours'), not as the object in this idiomatic expression. 'Your' is wrong because it is a possessive adjective that must be followed by a noun, and cannot stand alone as the object here.",category:"Grammar"},
  {id:"p5e2_8",question:"The CEO spoke for _____ in the press conference.",options:["A) herself","B) her","C) she","D) hers"],answer:"A",explanation:"'Herself' is correct because 'speak for oneself' is a set expression using a reflexive pronoun, and it emphasizes that the CEO represented her own views without a spokesperson. 'Her' is wrong because the object pronoun 'her' would imply speaking on behalf of a different person, not the subject herself. 'She' is wrong because it is a subject pronoun and cannot serve as the object of the preposition 'for'. 'Hers' is wrong because it is a possessive pronoun indicating ownership and does not fit the idiomatic expression 'speak for ___'.",category:"Grammar"},
  {id:"p5e2_9",question:"The company prides _____ on its outstanding customer support.",options:["A) it","B) its","C) itself","D) them"],answer:"C",explanation:"'Itself' is correct because 'pride itself on' is a fixed reflexive verb phrase where the subject ('the company') and the object must refer to the same entity, requiring a reflexive pronoun. 'It' is wrong because it is a standard third-person singular object pronoun referring to a different entity, which breaks the reflexive relationship. 'Its' is wrong because it is a possessive adjective and must precede a noun; it cannot serve as the object of a verb. 'Them' is wrong because it is a third-person plural pronoun and does not agree with the singular subject 'the company'.",category:"Grammar"},
  {id:"p5e2_10",question:"The technician repaired the machine _____ without calling an outside contractor.",options:["A) himself","B) his","C) him","D) he"],answer:"A",explanation:"'Himself' is correct because the reflexive pronoun is used here for emphasis, showing that the technician — and no one else — performed the repair, without any outside help. 'His' is wrong because it is a possessive adjective that must precede a noun (e.g., 'his tools'), and cannot serve as an emphatic standalone element. 'Him' is wrong because it is an object pronoun referring to a different person, implying someone repaired him, which makes no sense in context. 'He' is wrong because it is a subject pronoun and already appears implicitly as the subject; repeating it in object or emphatic position is grammatically incorrect.",category:"Grammar"},
  {id:"p5e2_11",question:"Please turn _____ the lights before leaving the office.",options:["A) on","B) off","C) up","D) in"],answer:"B",explanation:"'Turn off' is correct because this phrasal verb means to stop an electrical device from operating, which is the intended meaning when leaving the office. 'Turn on' is wrong because it means to activate or switch something on, the opposite of what is needed before leaving. 'Turn up' is wrong because it means to increase the intensity of something (e.g., the volume), not to switch it off. 'Turn in' is wrong because it means to submit something or go to bed, not to switch off a light.",category:"Phrasal Verb"},
  {id:"p5e2_12",question:"We ran _____ of printer paper, so please order more.",options:["A) short","B) out","C) low","D) off"],answer:"B",explanation:"'Run out of' is correct because this phrasal verb means to have no remaining supply of something, which matches the context of needing to order more. 'Run short of' is a valid expression, but 'short' alone after 'ran _____ of' does not form the standard phrase; 'run short of' works as a full unit but 'ran short of' would need 'short' not to fill a single blank with 'of' already provided. 'Run low' means to have very little remaining but uses a different structure ('run low on'), not 'run low of'. 'Run off' means to leave quickly or to produce copies, and does not fit the meaning of depleting a supply.",category:"Phrasal Verb"},
  {id:"p5e2_13",question:"The meeting was called _____ due to the director's illness.",options:["A) back","B) out","C) off","D) up"],answer:"C",explanation:"'Called off' is correct because this phrasal verb means to cancel a planned event, which fits the context of a meeting cancelled because of illness. 'Called back' means to return a phone call or to recall someone, not to cancel a meeting. 'Called out' means to shout something, to challenge someone, or to summon emergency services, not to cancel an event. 'Called up' means to telephone someone or to summon someone for military service, and does not mean to cancel.",category:"Phrasal Verb"},
  {id:"p5e2_14",question:"Please fill _____ this application form and return it by Friday.",options:["A) in","B) up","C) out","D) both A and C"],answer:"D",explanation:"'Both A and C' is correct because 'fill in' (British English) and 'fill out' (American English) are both standard expressions meaning to complete a form by writing in the required information. 'Fill up' is wrong because it means to make something completely full (e.g., 'fill up the tank'), not to complete a written form. The option 'both A and C' is preferred over choosing either alone because both are widely accepted in international business contexts and neither is incorrect.",category:"Phrasal Verb"},
  {id:"p5e2_15",question:"Could you look _____ this report and let me know if anything seems wrong?",options:["A) at","B) into","C) over","D) both A and C"],answer:"D",explanation:"'Both A and C' is correct because 'look at' (to examine or check something) and 'look over' (to review something carefully) are both natural and correct ways to ask someone to examine a report. 'Look into' is wrong in this context because it means to investigate a problem or matter in depth, which implies a formal inquiry rather than simply reviewing a document. The option 'both A and C' reflects that either preposition produces a grammatically and semantically valid sentence in a business setting.",category:"Phrasal Verb"},
  {id:"p5e2_16",question:"He handed _____ the signed contracts to the legal team.",options:["A) over","B) in","C) out","D) both A and B"],answer:"D",explanation:"'Both A and B' is correct because 'hand over' (to transfer possession or authority to another party) and 'hand in' (to submit something to a responsible party) both describe the act of delivering the contracts to the legal team. 'Hand out' is wrong because it means to distribute items to multiple people (e.g., handing out flyers), not to transfer documents to a specific team. The two correct options reflect different but equally valid nuances: transferring (hand over) versus submitting (hand in).",category:"Phrasal Verb"},
  {id:"p5e2_17",question:"The new manager wants to set _____ a meeting with each team member.",options:["A) up","B) out","C) off","D) in"],answer:"A",explanation:"'Set up' is correct because this phrasal verb means to arrange or organize something, and 'set up a meeting' is the standard business expression for scheduling one. 'Set out' means to begin a journey or to lay out information in a structured way, not to arrange a meeting. 'Set off' means to begin a journey or to trigger an alarm, neither of which fits the context of organizing a meeting. 'Set in' means to begin and become established (used for weather or moods), and does not collocate with 'meeting'.",category:"Phrasal Verb"},
  {id:"p5e2_18",question:"She was asked to look _____ the junior team while the supervisor was away.",options:["A) after","B) over","C) into","D) at"],answer:"A",explanation:"'Look after' is correct because this phrasal verb means to take care of or be responsible for someone, which fits the context of supervising the junior team in the supervisor's absence. 'Look over' means to review or inspect something (usually a document), not to supervise people. 'Look into' means to investigate a matter or problem, not to take care of a group of people. 'Look at' means to direct one's eyes toward something or to examine it briefly, and does not carry the meaning of supervision or care.",category:"Phrasal Verb"},
  {id:"p5e2_19",question:"The marketing team will come _____ with a new campaign idea by Friday.",options:["A) out","B) up","C) in","D) over"],answer:"B",explanation:"'Come up with' is correct because this three-word phrasal verb means to produce or think of an idea or solution, which is exactly what the marketing team must do. 'Come out with' can sometimes mean to release a product, but it does not naturally collocate with 'idea' in this context. 'Come in with' is not a standard phrasal verb in this context and does not convey producing or devising an idea. 'Come over with' is not a recognized phrasal verb in this business context and produces no meaningful sentence.",category:"Phrasal Verb"},
  {id:"p5e2_20",question:"Could you put _____ the call to tomorrow morning?",options:["A) off","B) back","C) through","D) both A and B"],answer:"D",explanation:"'Both A and B' is correct because 'put off' (to postpone or delay) and 'put back' (to reschedule to a later time) both describe moving the call to tomorrow morning. 'Put through' is wrong because it means to connect a phone call to someone, the opposite of delaying it. The two correct options share the meaning of deferring the call but with slightly different emphasis: 'put off' stresses postponement, while 'put back' stresses rescheduling to a later slot.",category:"Phrasal Verb"},
  {id:"p5e2_21",question:"Please switch _____ your mobile phones during the presentation.",options:["A) off","B) out","C) down","D) over"],answer:"A",explanation:"'Switch off' is correct because this phrasal verb means to turn a device off completely, which is the required action for mobile phones during a presentation. 'Switch out' means to exchange or replace one thing with another, not to deactivate a device. 'Switch down' is not a standard phrasal verb and does not convey the idea of turning off a phone. 'Switch over' means to change to a different channel or system, not to deactivate a device.",category:"Phrasal Verb"},
  {id:"p5e2_22",question:"The HR department is looking _____ several complaints from employees.",options:["A) over","B) into","C) at","D) after"],answer:"B",explanation:"'Looking into' is correct because this phrasal verb means to investigate or examine a matter in detail, which is the appropriate action for HR handling employee complaints. 'Looking over' means to review or check a document, and while it can apply to reports, it does not carry the sense of formal investigation required here. 'Looking at' simply means to examine or consider briefly, without the implication of a thorough investigation. 'Looking after' means to take care of someone or something, not to investigate complaints.",category:"Phrasal Verb"},
  {id:"p5e2_23",question:"We had to turn _____ the candidate because she lacked the required experience.",options:["A) away","B) down","C) off","D) both A and B"],answer:"D",explanation:"'Both A and B' is correct because 'turn away' (to refuse to accept or send someone away) and 'turn down' (to reject) both describe the act of not accepting the candidate. 'Turn off' means to switch something off or to cause someone to lose interest or attraction, not to reject a job candidate. The two correct options reflect slightly different nuances: 'turn away' emphasizes the act of sending someone away, while 'turn down' emphasizes the decision to reject.",category:"Phrasal Verb"},
  {id:"p5e2_24",question:"The project was held _____ because of budget approval delays.",options:["A) back","B) up","C) off","D) both A and B"],answer:"D",explanation:"'Both A and B' is correct because 'held back' (prevented from moving forward or delayed) and 'held up' (caused to be delayed) both describe a project that could not proceed due to budget delays. 'Held off' means to delay doing something by choice or to keep something at a distance, and while it can imply delay, it typically involves a deliberate decision rather than being caused by an external factor. The two correct options are near-synonyms here: 'held back' focuses on being restrained, while 'held up' focuses on the disruption to progress.",category:"Phrasal Verb"},
  {id:"p5e2_25",question:"The sales team needs to follow _____ with clients after the trade show.",options:["A) up","B) out","C) in","D) through"],answer:"A",explanation:"'Follow up with' is correct because this phrasal verb means to make further contact with someone after an initial meeting, which is precisely what the sales team must do after the trade show. 'Follow out' is not a standard phrasal verb in this context and does not mean to make further contact. 'Follow in' typically appears in expressions like 'follow in someone's footsteps' and does not mean to contact clients. 'Follow through' means to complete something you have started or committed to, which is related but does not specifically mean making further contact with clients.",category:"Phrasal Verb"},
  {id:"p5e2_26",question:"The package was too heavy _____ carry alone.",options:["A) for","B) to","C) so","D) that"],answer:"B",explanation:"'To' is correct because the structure 'too + adjective + to + base infinitive' expresses that something is so extreme that a particular action is impossible or impractical ('too heavy to carry'). 'For' is wrong here because 'for' introduces a noun or pronoun in this structure (e.g., 'too heavy for one person'), not a bare infinitive. 'So' is wrong because 'so' pairs with 'that' in the structure 'so...that,' not with a bare infinitive directly. 'That' is wrong because while 'so heavy that' is a valid structure, it requires 'so' before the adjective, not 'too'.",category:"Grammar"},
  {id:"p5e2_27",question:"This report isn't detailed _____ to submit to the board.",options:["A) so","B) enough","C) too","D) very"],answer:"B",explanation:"'Enough' is correct because the structure 'adjective + enough + to + infinitive' expresses sufficiency (or in a negative sentence, insufficiency), and 'enough' must always follow the adjective it modifies. 'So' is wrong because 'so' is an intensifier that pairs with 'that' in a result clause (e.g., 'so detailed that'), not directly with 'to + infinitive'. 'Too' is wrong because 'too + adjective + to' expresses excess that prevents an action, but the sentence negates 'detailed,' so 'too' would create a confusing double negative meaning. 'Very' is wrong because it is a simple intensifier and does not create the grammatical structure needed to express sufficiency with a following infinitive.",category:"Grammar"},
  {id:"p5e2_28",question:"The room was _____ small to hold all 200 attendees.",options:["A) very","B) quite","C) too","D) enough"],answer:"C",explanation:"'Too' is correct because the structure 'too + adjective + to + infinitive' expresses that the degree of a quality makes an action impossible — the room was so small that it could not hold 200 people. 'Very' is wrong because 'very small to hold' is not a grammatical structure; 'very' intensifies an adjective but does not create a link to an infinitive expressing impossibility. 'Quite' is wrong because it is a degree adverb meaning 'fairly' or 'rather,' and 'quite small to hold' does not form a standard grammatical construction with an infinitive. 'Enough' is wrong because it follows the adjective (e.g., 'large enough to hold') and expresses sufficiency, not excess; 'small enough to hold' would convey the opposite meaning.",category:"Grammar"},
  {id:"p5e2_29",question:"She speaks English well _____ to give the keynote address.",options:["A) enough","B) too","C) very","D) quite"],answer:"A",explanation:"'Enough' is correct because after an adverb, 'enough' follows it to form the structure 'adverb + enough + to + infinitive,' expressing that the degree of ability is sufficient for a task ('speaks well enough to give'). 'Too' is wrong because 'too well to give' would mean that her level of English proficiency somehow prevents her from giving the speech, which is the opposite of the intended meaning. 'Very' is wrong because 'speaks English well very to give' is not a grammatical structure; 'very' modifies adjectives and adverbs but does not link them to infinitives of result. 'Quite' is wrong because 'quite' is a degree adverb meaning 'fairly,' and 'well quite to give' is not a grammatical construction.",category:"Grammar"},
  {id:"p5e2_30",question:"The contract was _____ complex for a non-lawyer to understand easily.",options:["A) very","B) quite","C) too","D) enough"],answer:"C",explanation:"'Too' is correct because the structure 'too + adjective + for + noun/pronoun + to + infinitive' expresses that something is so extreme that it creates difficulty for a specific person or group ('too complex for a non-lawyer to understand'). 'Very' is wrong because 'very complex for a non-lawyer to understand' is a plausible phrase but does not grammatically signal impossibility or difficulty through a standard construction; 'too' is required for this structure. 'Quite' is wrong because it means 'fairly' or 'rather' and does not work in the 'too...for...to' structure. 'Enough' is wrong because it expresses sufficiency ('complex enough for...') and would change the meaning to indicate the contract is sufficiently complex, losing the sense that this complexity is a barrier.",category:"Grammar"},
  {id:"p5e2_31",question:"_____ the manager nor the assistant was in the office yesterday.",options:["A) Both","B) Either","C) Neither","D) Not"],answer:"C",explanation:"'Neither' is correct because 'neither...nor' is the standard correlative conjunction used to indicate that two subjects both fail to satisfy a condition, and it requires a singular verb when both subjects are singular. 'Both' is wrong because 'both...and' indicates that two subjects are included, which is the opposite meaning of what the sentence requires. 'Either' is wrong because 'either...or' presents a choice or possibility between two options, not a negative statement about both. 'Not' is wrong because 'not...nor' is not a standard correlative conjunction structure in English; 'neither...nor' is the correct negative pair.",category:"Grammar"},
  {id:"p5e2_32",question:"_____ employees are required to complete the e-learning modules.",options:["A) All","B) Every","C) Each","D) Both"],answer:"A",explanation:"'All' is correct because 'all' can directly precede a plural countable noun without 'of' to mean the entire group ('all employees'), making it grammatically and semantically correct. 'Every' is wrong because 'every' must be followed by a singular countable noun and a singular verb (e.g., 'every employee is'), not a plural noun like 'employees'. 'Each' is wrong for the same reason — 'each' also takes a singular noun (e.g., 'each employee') and cannot precede the plural 'employees'. 'Both' is wrong because 'both' refers to exactly two items and implies a specific pair was previously identified, not the entire workforce.",category:"Grammar"},
  {id:"p5e2_33",question:"You can pay _____ cash or credit card.",options:["A) with either","B) neither","C) both","D) each"],answer:"A",explanation:"'With either' is correct because 'either...or' is the correlative conjunction used to present a choice between two options, and 'with' is required as the preposition for the method of payment ('pay with cash or credit card'). 'Neither' is wrong because 'neither...nor' is used to negate both options, which contradicts the sentence's meaning that payment is possible. 'Both' is wrong because while 'both...and' includes both options, saying you can pay with 'both cash and credit card' simultaneously is not idiomatic for presenting payment choices. 'Each' is wrong because 'each' refers to individual items separately and does not function as a correlative conjunction presenting a payment choice.",category:"Grammar"},
  {id:"p5e2_34",question:"_____ the CEO and the CFO attended the investor day.",options:["A) Neither","B) Both","C) Either","D) Each"],answer:"B",explanation:"'Both' is correct because 'both...and' is the correlative conjunction used to indicate that two subjects are equally included in an action, meaning the CEO and CFO each attended. 'Neither' is wrong because 'neither...nor' expresses that two subjects did not do something, which contradicts the intended meaning that both executives attended. 'Either' is wrong because 'either...or' presents an alternative or choice, implying only one of the two attended, not both. 'Each' is wrong because while 'each' can refer to two people individually, 'each the CEO and the CFO' is not a grammatical structure in English.",category:"Grammar"},
  {id:"p5e2_35",question:"_____ department must submit a monthly report.",options:["A) All","B) Both","C) Every","D) Either"],answer:"C",explanation:"'Every' is correct because it is used before a singular countable noun to refer to all members of a group individually, and 'every department must' takes a singular verb correctly. 'All' is wrong because 'all' requires a plural noun ('all departments must'), and cannot directly precede a singular noun like 'department' in this structure. 'Both' is wrong because 'both' refers to exactly two previously identified items, not to an unspecified number of departments in a company. 'Either' is wrong because 'either' refers to one of two options and implies a choice, whereas the sentence applies the rule to all departments without exception.",category:"Grammar"},
  {id:"p5e2_36",question:"He used _____ commute by train, but he now drives to work.",options:["A) to","B) for","C) at","D) by"],answer:"A",explanation:"'Used to' is correct because 'used to + base infinitive' is the standard structure for describing a past habit or state that no longer exists, perfectly matching the contrast with 'but he now drives'. 'Used for' is wrong because 'used for' means 'employed as a tool or method for a purpose' (e.g., 'a hammer is used for driving nails'), which does not describe a past personal habit. 'Used at' is wrong because 'at' is not a preposition that forms a meaningful phrase with 'used' in the context of past habits. 'Used by' is wrong because 'used by' describes who uses something (e.g., 'the tool was used by the technician') and does not express a past habitual action.",category:"Grammar"},
  {id:"p5e2_37",question:"She is used _____ working late; she has done it for years.",options:["A) to","B) for","C) by","D) in"],answer:"A",explanation:"'Used to' is correct here because 'be used to + gerund' means to be accustomed to something through repeated experience, and 'working' is the gerund that follows 'to' in this structure. 'Used for' is wrong because 'used for' expresses purpose (e.g., 'a tool used for cutting') and cannot describe a person being accustomed to an activity. 'Used by' is wrong because it describes the agent who uses something in a passive construction, not personal familiarity with an activity. 'Used in' is wrong because it indicates the context in which something is employed (e.g., 'a term used in medicine'), not personal habituation.",category:"Grammar"},
  {id:"p5e2_38",question:"The new system took getting _____ to, but it is now much faster.",options:["A) used","B) accustomed","C) familiar","D) both A and B"],answer:"A",explanation:"'Getting used to' is correct because 'get used to + noun/gerund' is the standard idiomatic expression meaning to become accustomed to something over time, and 'getting used to' fits perfectly in the fixed phrase 'took getting used to.' 'Accustomed' is wrong because 'get accustomed to' is grammatically possible in other contexts but 'took getting accustomed to' is not the natural idiomatic phrasing that native speakers use. 'Familiar' is wrong because 'get familiar with' requires 'with,' not 'to,' and 'took getting familiar to' is ungrammatical. 'Both A and B' is wrong because while 'get accustomed to' exists, the phrasing 'took getting accustomed to' is not idiomatic, so only A produces the natural set phrase.",category:"Grammar"},
  {id:"p5e2_39",question:"I am not used _____ giving presentations, so I was quite nervous.",options:["A) to","B) for","C) of","D) with"],answer:"A",explanation:"'Used to' is correct because 'be used to + gerund' requires the preposition 'to' followed by a gerund ('giving') to express that someone is not accustomed to a particular activity. 'Used for' is wrong because 'for' introduces purpose rather than familiarity, making 'not used for giving' meaningless in this personal context. 'Used of' is wrong because 'of' does not collocate with 'used' in this idiomatic expression; there is no standard construction 'used of doing something'. 'Used with' is wrong because 'with' does not form a standard phrase here; the correct preposition for expressing habituation is always 'to' in this structure.",category:"Grammar"},
  {id:"p5e2_40",question:"The company _____ outsource most of its HR functions, but it now has an in-house team.",options:["A) uses to","B) used to","C) is used to","D) was used to"],answer:"B",explanation:"'Used to' is correct because 'used to + base infinitive' expresses a past habit or situation that no longer exists, which matches the contrast with the present situation of having an in-house team. 'Uses to' is wrong because 'uses to' is not a grammatical form in English; the correct past habit form is always 'used to,' never 'uses to'. 'Is used to' is wrong because 'is used to + gerund' means to be currently accustomed to doing something, not to express a discontinued past practice. 'Was used to' is wrong because 'was used to + gerund' means was accustomed to an activity in the past, but the sentence requires 'used to + infinitive' to describe a discontinued past habit.",category:"Grammar"},
  {id:"p5e2_41",question:"I _____ the printer set up for the presentation.",options:["A) got","B) made","C) let","D) had"],answer:"D",explanation:"'Had' is correct because the causative structure 'have + object + past participle' ('had the printer set up') means to arrange for someone else to perform an action, which is the standard business causative. 'Got' is wrong in this context because while 'get + object + past participle' forms a causative, 'got the printer set up' is informal; in formal business English, 'have' is the standard causative verb and 'had the printer set up' is the preferred professional phrasing. 'Made' is wrong because 'make + object + base infinitive' means to force someone to do something (e.g., 'made him work'), not to arrange for something to be done. 'Let' is wrong because 'let + object + base infinitive' means to allow someone to do something, not to arrange for a task to be completed.",category:"Grammar"},
  {id:"p5e2_42",question:"She _____ her assistant book all the flights in advance.",options:["A) made","B) had","C) let","D) both B and C"],answer:"D",explanation:"'Both B and C' is correct because 'had her assistant book' (causative: arranged for the assistant to book the flights) and 'let her assistant book' (permissive: gave the assistant permission to book the flights) are both grammatically valid causative/permissive structures. 'Made' is wrong in this context because while 'make + object + infinitive' is grammatically possible, it implies forcing someone against their will, which is an unlikely nuance for a routine office task. The two correct options are preferred because 'had' implies arrangement and 'let' implies permission, both of which are natural and appropriate here.",category:"Grammar"},
  {id:"p5e2_43",question:"The manager _____ the entire team work overtime that weekend.",options:["A) made","B) had","C) let","D) allowed"],answer:"A",explanation:"'Made' is correct because 'make + object + base infinitive' is used to express that someone was compelled or required to do something, and the context of requiring the whole team to work overtime implies an authoritative directive. 'Had' is wrong here because 'have + object + base infinitive' implies arranging for something to be done, with less connotation of compulsion, making it a weaker fit when the meaning is to force. 'Let' is wrong because 'let + object + base infinitive' means to allow or permit, not to compel, implying the team chose to work overtime. 'Allowed' is wrong because 'allowed the team to work' (using 'to' + infinitive) means to permit, not to require, and carries no sense of obligation.",category:"Grammar"},
  {id:"p5e2_44",question:"We _____ our website redesigned by a professional agency.",options:["A) had","B) made","C) let","D) got"],answer:"D",explanation:"'Got' is correct because 'get + object + past participle' ('got our website redesigned') is a causative structure meaning to arrange for something to be done by someone else, and 'got' is the more idiomatic informal business phrasing for this practical arrangement context. 'Made' is wrong because 'make + object + past participle' is not the standard causative form; 'make' uses 'make + object + base infinitive' (to compel action by a person), not past participle for inanimate results. 'Let' is wrong because 'let + object + base infinitive' expresses permission, not arranging for a service to be performed. 'Had' is wrong as the specific answer here because while 'have + object + past participle' is also a valid causative, the question targets 'got' as the idiomatic choice for a practical arrangement made with an external agency.",category:"Grammar"},
  {id:"p5e2_45",question:"He _____ the IT team fix the issue immediately.",options:["A) had","B) made","C) let","D) got"],answer:"A",explanation:"'Had' is correct because 'have + object + base infinitive' ('had the IT team fix') is the causative structure meaning to arrange for or direct someone to perform an action, which fits the managerial context of directing the IT team. 'Made' is wrong because while 'make + object + base infinitive' is grammatically correct, it implies compulsion or force, which is too strong a nuance for a professional instruction to a support team. 'Let' is wrong because it means to permit or allow, implying the IT team needed permission to fix the issue rather than being directed to do so. 'Got' is wrong in this specific answer because 'get + object + to + base infinitive' requires 'to' before the verb ('got the IT team to fix'), so 'got...fix' without 'to' is ungrammatical.",category:"Grammar"},
  {id:"p5e2_46",question:"The conference _____ place in Singapore this year.",options:["A) took","B) takes","C) has taken","D) taking"],answer:"A",explanation:"'Took' is correct because 'take place' is the fixed expression for an event occurring, and the simple past tense is used because the conference occurred during a specific completed period ('this year' used as a past reference). 'Takes' is wrong because the present simple 'takes place' would imply this is a regular, recurring event rather than a specific past occurrence. 'Has taken' is wrong because the present perfect emphasizes a connection to the present, but the sentence presents this as a completed factual statement about the past. 'Taking' is wrong because it is a present participle that cannot function as the main verb without an auxiliary verb such as 'is'.",category:"Grammar"},
  {id:"p5e2_47",question:"She gave _____ smoking after the doctor's advice.",options:["A) up","B) in","C) out","D) over"],answer:"A",explanation:"'Gave up' is correct because this phrasal verb means to stop doing something permanently, which precisely fits the context of quitting smoking following medical advice. 'Gave in' means to surrender or yield to pressure from someone, not to stop a personal habit. 'Gave out' means to distribute items or to stop functioning (e.g., the engine gave out), not to quit an activity. 'Gave over' means to hand something to someone else or to stop doing something in British informal usage, but it does not collocate naturally with 'smoking' the way 'gave up' does.",category:"Phrasal Verb"},
  {id:"p5e2_48",question:"The board decided to take _____ a new strategic partner.",options:["A) on","B) in","C) up","D) off"],answer:"A",explanation:"'Take on' is correct because this phrasal verb means to accept responsibility for, engage with, or bring on board someone or something, which fits the business context of accepting a new strategic partner. 'Take in' means to accommodate someone, to absorb information, or to deceive someone, none of which fits the meaning of adding a strategic partner. 'Take up' means to begin a hobby, to occupy space or time, or to raise a matter for discussion, none of which matches bringing on a business partner. 'Take off' means to depart (for a plane or person) or to become successful rapidly, and does not mean to engage with or accept a partner.",category:"Phrasal Verb"},
  {id:"p5e2_49",question:"The intern was asked to sort _____ the files in the archive room.",options:["A) out","B) through","C) up","D) both A and B"],answer:"D",explanation:"'Both A and B' is correct because 'sort out' (to organize or put in order) and 'sort through' (to go through a collection examining each item) are both valid descriptions of what the intern was doing with the archive files. 'Sort up' is not a standard phrasal verb in English and does not convey any meaning related to organizing or examining files. The two correct options reflect complementary actions: 'sort out' emphasizes organizing, while 'sort through' emphasizes the process of going through each file.",category:"Phrasal Verb"},
  {id:"p5e2_50",question:"The supervisor had to step _____ as team leader due to a health issue.",options:["A) back","B) down","C) away","D) both B and C"],answer:"D",explanation:"'Both B and C' is correct because 'step down' (to resign from a position of authority) and 'step away' (to withdraw from a role or responsibility) both describe leaving or reducing the team leader role due to health, making both B and C natural choices. 'Step back' is wrong because while 'step back from a role' can suggest reducing involvement, option A in this question is 'back,' and 'step back' does not specifically mean formally vacating a leadership title the way 'step down' or 'step away' do. 'Step out' means to leave a room briefly, not to resign from a leadership position, so it is not appropriate here.",category:"Phrasal Verb"},
  {id:"p5e2_51",question:"The flight was delayed _____ three hours due to fog.",options:["A) for","B) by","C) during","D) in"],answer:"B",explanation:"'By' is correct because 'delayed by + amount of time' is the standard structure to express the size or extent of a delay ('delayed by three hours' means the delay caused it to be three hours late). 'For' is wrong because 'delayed for three hours' describes a duration of waiting, which is not the same as stating how much later the flight arrived; 'by' is the correct preposition to express the amount by which a schedule was pushed back. 'During' is wrong because it means 'throughout a period of time' and does not express an amount of delay. 'In' is wrong because 'in three hours' indicates a point in the future rather than the magnitude of a delay.",category:"Preposition"},
  {id:"p5e2_52",question:"She is responsible _____ overseeing the daily operations of the branch.",options:["A) for","B) of","C) with","D) to"],answer:"A",explanation:"'Responsible for' is correct because 'for' is the fixed preposition that collocates with 'responsible' when describing duties or areas of oversight in a professional context. 'Responsible of' is wrong because 'of' does not collocate with 'responsible' in English; this is a common interference error from other languages. 'Responsible with' is wrong because 'with' does not form a standard prepositional phrase with 'responsible' in the sense of having a duty. 'Responsible to' is wrong because 'responsible to someone' means accountable to a person (e.g., 'responsible to the board'), not in charge of a task or area.",category:"Preposition"},
  {id:"p5e2_53",question:"The decision was made _____ consultation with all stakeholders.",options:["A) in","B) after","C) with","D) both A and C"],answer:"D",explanation:"'Both A and C' is correct because 'in consultation with all stakeholders' (meaning as part of a collaborative process with them) and 'with consultation with all stakeholders' (using 'with' to indicate the means or manner of the decision-making) are both acceptable ways to express that stakeholders were involved. 'After' is wrong because 'after consultation with all stakeholders' implies the decision was made only once the consultation was already finished, which slightly changes the meaning from the intended sense of stakeholder involvement in the process. The two accepted options both naturally complete the sentence and reflect that the consultation was part of the decision-making.",category:"Preposition"},
  {id:"p5e2_54",question:"The manager was pleased _____ the team's progress.",options:["A) at","B) by","C) with","D) both B and C"],answer:"D",explanation:"'Both B and C' is correct because 'pleased with' and 'pleased by' are both grammatically and semantically acceptable in English, with 'pleased with' being the more common collocation and 'pleased by' also used naturally in formal contexts. 'Pleased at' can appear in informal usage (e.g., 'pleased at the news') but is less standard in formal business writing when expressing satisfaction with someone's work. The two accepted options reflect the flexibility of the adjective 'pleased' to take more than one preposition without a meaningful change in the sentence.",category:"Preposition"},
  {id:"p5e2_55",question:"The policy is aimed _____ reducing unnecessary spending.",options:["A) for","B) at","C) to","D) toward"],answer:"B",explanation:"'Aimed at' is correct because 'aimed at + gerund' is the fixed prepositional phrase meaning designed or intended to achieve a particular result ('aimed at reducing'). 'Aimed for' is wrong because 'aim for' means to target a goal (e.g., 'aim for success'), but when followed by a gerund indicating a purpose, the correct preposition is 'at,' not 'for.' 'Aimed to' is wrong because 'aim to + infinitive' is used with a subject that has an intention (e.g., 'we aim to reduce'), not in the passive structure 'is aimed to.' 'Aimed toward' is wrong because 'toward' suggests direction rather than design for a purpose, and 'aimed toward reducing' is not idiomatic in formal business English.",category:"Preposition"},
  {id:"p5e2_56",question:"She apologized _____ the delay in responding to the client.",options:["A) about","B) for","C) of","D) to"],answer:"B",explanation:"'Apologized for' is correct because 'apologize for' is the fixed prepositional collocation used when expressing regret about a specific action or situation. 'Apologized about' is wrong because while 'about' can follow 'apologize' informally in some dialects, 'apologize for' is the standard formal construction required in business English. 'Apologized of' is wrong because 'of' does not collocate with 'apologize' in any standard English construction. 'Apologized to' is wrong because 'apologize to' introduces the person receiving the apology (e.g., 'she apologized to the client'), not the reason for the apology.",category:"Preposition"},
  {id:"p5e2_57",question:"Please inform us _____ any changes to your schedule.",options:["A) about","B) of","C) on","D) both A and B"],answer:"D",explanation:"'Both A and B' is correct because 'inform someone about something' and 'inform someone of something' are both standard and widely accepted usages in both formal and informal English. 'Inform on' is wrong because 'inform on someone' means to report someone to the authorities, which is a completely different meaning from notifying someone of a change. The two correct prepositions ('about' and 'of') are interchangeable in this context, with 'of' being slightly more formal.",category:"Preposition"},
  {id:"p5e2_58",question:"He was promoted _____ Deputy General Manager last quarter.",options:["A) as","B) to","C) into","D) both B and C"],answer:"B",explanation:"'Promoted to' is correct because 'promote to + title' is the standard fixed expression describing advancement to a new position in a professional hierarchy ('promoted to Deputy General Manager'). 'Promoted as' is wrong because 'as' is used for roles or descriptions (e.g., 'hired as a manager'), not for the result of a promotion to a specific title. 'Promoted into' is wrong because while 'into' can suggest movement into a role informally, 'promote into' is not the standard collocation; 'promote to' is universally correct in formal and business English. 'Both B and C' is wrong because 'into' is non-standard with 'promote,' making option C incorrect and disqualifying the combined option.",category:"Preposition"},
  {id:"p5e2_59",question:"The new policy applies _____ all employees, regardless of seniority.",options:["A) for","B) at","C) to","D) with"],answer:"C",explanation:"'Applies to' is correct because 'apply to' is the fixed prepositional verb meaning to be relevant to or to affect a particular group or situation, which is the intended meaning here. 'Applies for' is wrong because 'apply for' means to formally request something (e.g., 'apply for a visa'), not to be relevant to a group of people. 'Applies at' is wrong because 'at' does not form a meaningful phrase with 'apply' in the sense of a rule being in effect for a group. 'Applies with' is wrong because 'with' does not collocate with 'apply' in this context; it produces no standard English meaning.",category:"Preposition"},
  {id:"p5e2_60",question:"The team was divided _____ opinion on the new marketing strategy.",options:["A) about","B) in","C) on","D) over"],answer:"D",explanation:"'Divided over' is correct because 'divided over' is the natural prepositional collocation expressing that a group holds differing opinions about a particular issue or decision. 'Divided about' is not the standard collocation; while 'about' can appear informally, 'over' is the fixed and preferred preposition in formal business English. 'Divided in' does not form a standard phrase in this context; 'divided in opinion' is archaic and not in common modern use. 'Divided on' is wrong because while 'divided on an issue' is sometimes used, 'divided over' is the primary and most widely accepted collocation when describing disagreement about a decision or strategy in modern formal usage.",category:"Preposition"},
  {id:"p5e2_61",question:"All files must be _____ in clearly labeled folders.",options:["A) store","B) stored","C) storing","D) stores"],answer:"B",explanation:"'Stored' is correct because 'must be + past participle' forms the passive modal construction used to express a requirement that something be in a particular state ('must be stored'). 'Store' is wrong because the base form cannot follow 'must be'; the passive requires a past participle, and 'must store' (active) would need a subject that performs the action. 'Storing' is wrong because the present participle cannot complete the passive modal structure 'must be'; 'be storing' would form the continuous aspect, not the passive voice. 'Stores' is wrong because it is the third-person singular present active form and cannot follow 'must be' to form a passive construction.",category:"Grammar"},
  {id:"p5e2_62",question:"The training _____ three days and covers all key software features.",options:["A) lasts","B) last","C) lasted","D) lasting"],answer:"A",explanation:"'Lasts' is correct because the third-person singular subject 'the training' requires the -s form in the present simple tense, which is used here to state a fixed fact about the program's duration. 'Last' is wrong because it is the base form, appropriate for subjects like I/you/we/they, but not for the singular 'the training.' 'Lasted' is wrong because the simple past describes a completed event in the past, whereas the sentence states a current, ongoing fact about the program. 'Lasting' is wrong because the present participle cannot function as the main verb without an auxiliary ('is lasting'), and the sentence pairs it with 'covers,' which is present simple.",category:"Grammar"},
  {id:"p5e2_63",question:"The office _____ renovated while staff worked from home.",options:["A) was","B) is","C) were","D) had"],answer:"A",explanation:"'Was' is correct because the office (singular subject) requires the singular past tense auxiliary 'was' to form the simple past passive ('was renovated'), describing a completed past action. 'Is' is wrong because it forms the present simple passive ('is renovated'), which would describe a current or general state rather than a past completed renovation. 'Were' is wrong because 'were' is the plural past form and does not agree with the singular subject 'the office.' 'Had' is wrong because 'had renovated' would form the active past perfect (implying the office performed the action), not the passive voice needed here.",category:"Grammar"},
  {id:"p5e2_64",question:"She had her business card _____ in three languages.",options:["A) print","B) prints","C) printed","D) printing"],answer:"C",explanation:"'Printed' is correct because the causative structure 'have + object + past participle' requires a past participle ('printed') to indicate that she arranged for someone else to print her business card. 'Print' is wrong because the base infinitive is used with 'have' only in the active causative structure 'have someone do something' (e.g., 'have him print'), not when the object is the thing affected. 'Prints' is wrong because the third-person singular present tense cannot follow 'had her business card' in a causative construction. 'Printing' is wrong because the present participle does not complete the causative 'have + object + past participle' structure; it would instead suggest an ongoing action.",category:"Grammar"},
  {id:"p5e2_65",question:"The flight _____ at 7:45 AM, so please arrive at the airport early.",options:["A) leaves","B) leave","C) is leaving","D) both A and C"],answer:"D",explanation:"'Both A and C' is correct because the present simple ('leaves') is used to describe scheduled timetabled events, while the present continuous ('is leaving') can describe an imminent or already-arranged future event — both are grammatically accepted ways to refer to a scheduled departure. 'Leave' is wrong because it is the base form used with I/you/we/they, not with the singular third-person subject 'the flight.' The two accepted options reflect a well-known grammatical rule in English: timetable events can be expressed with either the present simple or present continuous for the near future.",category:"Grammar"},
  {id:"p5e2_66",question:"There are _____ seats available in the auditorium.",options:["A) few","B) a few","C) little","D) a little"],answer:"B",explanation:"'A few' is correct because 'seats' is a countable plural noun, and 'a few' means 'some' (a small but positive number), conveying that there are seats available — a positive and helpful statement. 'Few' is wrong because without the article 'a,' it carries a negative implication (almost none), which contradicts the positive context of seats being available. 'Little' is wrong because it is used with uncountable nouns (e.g., 'little water'), not with countable plural nouns like 'seats.' 'A little' is wrong for the same reason — it modifies uncountable nouns, not countable plural nouns such as 'seats'.",category:"Grammar"},
  {id:"p5e2_67",question:"We have _____ time before the deadline; let's not rush.",options:["A) a few","B) few","C) a little","D) little"],answer:"C",explanation:"'A little' is correct because 'time' is an uncountable noun, and 'a little' means 'some' (a small but sufficient amount), conveying a positive message that there is still time and no need to rush. 'A few' is wrong because 'a few' collocates only with countable plural nouns, and 'time' is uncountable. 'Few' is wrong because it collocates with countable plural nouns, not with the uncountable noun 'time.' 'Little' is wrong because without the article 'a,' it carries a negative implication (almost no time), which contradicts the reassuring tone of 'let's not rush.'",category:"Grammar"},
  {id:"p5e2_68",question:"Unfortunately, there is _____ parking available near the venue.",options:["A) few","B) a few","C) little","D) a little"],answer:"C",explanation:"'Little' is correct because 'parking' is an uncountable noun, and 'little' (without 'a') means 'almost none,' conveying the negative implication signalled by 'unfortunately' — there is hardly any parking. 'Few' is wrong because it collocates with countable plural nouns, not with the uncountable noun 'parking.' 'A few' is wrong for the same reason — 'a few' requires a countable plural noun. 'A little' is wrong because while it also modifies uncountable nouns, 'a little' carries a positive meaning (some parking is available), which contradicts the unfortunate tone of the sentence.",category:"Grammar"},
  {id:"p5e2_69",question:"_____ employees know the full details of the acquisition.",options:["A) Little","B) Few","C) A little","D) A few"],answer:"B",explanation:"'Few' is correct because 'employees' is a countable plural noun, and 'few' (without 'a') expresses a negative meaning (almost none), which fits the implication that knowledge of the acquisition is restricted to very few people. 'Little' is wrong because it modifies uncountable nouns, not countable plural nouns like 'employees.' 'A little' is wrong for the same reason — it also modifies only uncountable nouns. 'A few' is wrong because while it collocates with countable plural nouns, 'a few' carries a positive implication (some employees know), which does not convey the restrictive or secretive nuance of the sentence.",category:"Grammar"},
  {id:"p5e2_70",question:"She has _____ experience with project management software.",options:["A) few","B) a few","C) a little","D) little"],answer:"C",explanation:"'A little' is correct because 'experience' is an uncountable noun, and 'a little' means 'some,' conveying a positive and helpful quantity — she does have some relevant experience. 'Few' is wrong because it collocates with countable plural nouns, not the uncountable noun 'experience.' 'A few' is wrong for the same reason. 'Little' is wrong because without the article 'a,' it implies almost no experience, which is a negative and unhelpful assessment that the sentence does not intend to convey.",category:"Grammar"},
  {id:"p5e2_71",question:"The CEO's speech was _____ and to the point.",options:["A) brief","B) briefly","C) brevity","D) briefing"],answer:"A",explanation:"'Brief' is correct because an adjective is needed here to function as the predicate complement after the linking verb 'was,' describing a quality of the CEO's speech ('brief and to the point'). 'Briefly' is wrong because it is an adverb that modifies verbs or adjectives, not one that can serve as a predicate complement after a linking verb describing a noun. 'Brevity' is wrong because it is a noun meaning the quality of being brief, and a noun cannot function as a predicate adjective in a compound predicate describing the speech. 'Briefing' is wrong because it is a noun (a meeting to provide information) or a gerund, and does not work as a predicate complement here.",category:"Word Form"},
  {id:"p5e2_72",question:"The results were _____ better than the team had expected.",options:["A) considerable","B) considerably","C) considerate","D) considered"],answer:"B",explanation:"'Considerably' is correct because an adverb is needed to modify the comparative adjective 'better,' indicating the degree to which the results exceeded expectations. 'Considerable' is wrong because it is an adjective and must modify a noun (e.g., 'a considerable improvement'), not an adjective like 'better.' 'Considerate' is wrong because it is an adjective meaning thoughtful or kind toward others, which is a completely different meaning unrelated to the degree of results. 'Considered' is wrong because it is a past participle or adjective meaning carefully thought about, and does not function as a degree adverb before 'better.'",category:"Word Form"},
  {id:"p5e2_73",question:"Her _____ attention to detail makes her ideal for quality control.",options:["A) keen","B) keenly","C) keenness","D) keened"],answer:"A",explanation:"'Keen' is correct because an adjective is needed to modify the noun 'attention,' and 'keen attention to detail' is a standard collocation meaning sharp or intense focus on details. 'Keenly' is wrong because it is an adverb that modifies verbs or adjectives (e.g., 'keenly observed'), not a noun like 'attention.' 'Keenness' is wrong because it is a noun meaning the quality of being keen, and two nouns placed next to each other ('keenness attention') does not form a grammatical noun phrase without additional structure. 'Keened' is wrong because there is no standard verb 'keen' that can be inflected as 'keened' in English in this context.",category:"Word Form"},
  {id:"p5e2_74",question:"The product has been _____ redesigned to improve user experience.",options:["A) complete","B) completely","C) completion","D) completed"],answer:"B",explanation:"'Completely' is correct because an adverb is required to modify the past participle 'redesigned,' indicating the extent of the redesign ('completely redesigned' means redesigned in its entirety). 'Complete' is wrong because it is an adjective or verb; as an adjective it must modify a noun (e.g., 'a complete redesign'), not a past participle in this adverb slot. 'Completion' is wrong because it is a noun referring to the state of being finished, and a noun cannot serve as an adverb modifying the past participle 'redesigned.' 'Completed' is wrong because it is another past participle or adjective and would create a confusing double-participle construction rather than an adverb-modified participle.",category:"Word Form"},
  {id:"p5e2_75",question:"The manager provided a _____ explanation of the new procedures.",options:["A) clear","B) clearly","C) clarity","D) clarify"],answer:"A",explanation:"'Clear' is correct because an adjective is needed to modify the noun 'explanation,' and 'a clear explanation' means one that is easy to understand, which is the intended meaning. 'Clearly' is wrong because it is an adverb that modifies verbs or adjectives (e.g., 'explained clearly'), not a noun like 'explanation.' 'Clarity' is wrong because it is a noun meaning the quality of being clear, and placing two nouns side by side ('clarity explanation') is not grammatically correct in English without a connecting structure. 'Clarify' is wrong because it is a verb meaning to make something clearer, and a verb cannot serve as an adjective modifying a noun in this position.",category:"Word Form"},
  {id:"p5e2_76",question:"I would like to _____ our meeting from Monday to Wednesday.",options:["A) move","B) shift","C) change","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'move a meeting,' 'shift a meeting,' and 'change a meeting' are all natural business English expressions for rescheduling an event to a different time. 'Move' is the most common collocate for rescheduling meetings in professional contexts. 'Shift' is also used in business language to mean rescheduling. 'Change' is the most general term and is equally valid when describing altering the time of a scheduled meeting.",category:"Vocabulary"},
  {id:"p5e2_77",question:"Could you _____ me with the sales figures by end of day?",options:["A) provide","B) supply","C) send","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'provide someone with,' 'supply someone with,' and 'send someone' are all grammatically correct and semantically appropriate ways of giving someone a document or piece of information. 'Provide me with the sales figures' is the most formal and common business phrasing. 'Supply me with the figures' is also professional and used in business contexts. 'Send me the sales figures' is equally correct and perhaps the most direct of the three options.",category:"Vocabulary"},
  {id:"p5e2_78",question:"The company will _____ a new benefits package to all staff next quarter.",options:["A) roll out","B) introduce","C) launch","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'roll out,' 'introduce,' and 'launch' all describe the act of making a new program, product, or policy available, which fits the context of implementing a new benefits package. 'Roll out' is particularly common in corporate language for gradually implementing a program across an organization. 'Introduce' is the most neutral and widely used term for presenting something new. 'Launch' implies a more public or formal announcement of the new package.",category:"Vocabulary"},
  {id:"p5e2_79",question:"The department will _____ three more engineers before the year-end.",options:["A) hire","B) recruit","C) onboard","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'hire,' 'recruit,' and 'onboard' all relate to bringing new staff into an organization, though at slightly different stages. 'Hire' refers to formally employing someone. 'Recruit' refers to the process of finding and attracting candidates. 'Onboard' refers to integrating new employees into the company, but in modern business usage it is also used to mean the full process of bringing someone on. All three are valid in this context.",category:"Vocabulary"},
  {id:"p5e2_80",question:"She asked her assistant to _____ all the meeting notes from this week.",options:["A) compile","B) gather","C) collate","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'compile,' 'gather,' and 'collate' all describe the process of collecting and organizing information from multiple sources into one place. 'Compile' means to produce a collection by assembling material from different sources. 'Gather' means to collect items together, often from various locations. 'Collate' specifically means to collect and combine in the correct order, making it especially fitting for meeting notes.",category:"Vocabulary"},
  {id:"p5e2_81",question:"The office _____ at 5:00 PM on weekdays and 1:00 PM on Saturdays.",options:["A) close","B) closes","C) is closing","D) will close"],answer:"B",explanation:"'Closes' is correct because the third-person singular subject 'the office' requires the -s form in the present simple tense, which is used for fixed scheduled routines such as opening and closing times. 'Close' is wrong because it is the base form used with I/you/we/they, not with the singular third-person subject 'the office.' 'Is closing' is wrong because the present continuous describes an action in progress at the moment of speaking or an imminent arrangement, not a fixed daily schedule. 'Will close' is wrong because while it expresses future intention, the present simple is the preferred tense for regular scheduled events and timetables.",category:"Grammar"},
  {id:"p5e2_82",question:"She has been _____ to the London office for the next two months.",options:["A) assigned","B) allocate","C) send","D) placing"],answer:"A",explanation:"'Assigned' is correct because 'has been assigned to' forms the present perfect passive, meaning a decision was recently made that she will be posted to the London office — the past participle 'assigned' is required after 'has been.' 'Allocate' is wrong because it is a base infinitive and cannot follow 'has been'; the passive requires a past participle, which would be 'allocated.' 'Send' is wrong because it is a base form; the correct past participle is 'sent,' and even then 'has been sent to' has a slightly different nuance from being formally assigned. 'Placing' is wrong because a present participle after 'has been' would form the present perfect continuous active ('has been placing'), not the passive voice.",category:"Grammar"},
  {id:"p5e2_83",question:"The equipment must be returned _____ good working condition.",options:["A) in","B) at","C) on","D) with"],answer:"A",explanation:"'In' is correct because 'in good working condition' is a fixed prepositional phrase meaning the equipment is functioning properly, and 'in' is the required preposition in this expression. 'At' is wrong because 'at' typically indicates a location or point in time (e.g., 'at the office,' 'at noon') and does not form a standard phrase with 'good working condition.' 'On' is wrong because 'on' indicates position on a surface or a topic (e.g., 'on the table,' 'on schedule') and does not collocate with 'good working condition.' 'With' is wrong because 'with' indicates accompaniment or a tool used (e.g., 'with care'), not the state or condition something must be returned in.",category:"Preposition"},
  {id:"p5e2_84",question:"The survey will take _____ five minutes to complete.",options:["A) approximate","B) approximately","C) approximation","D) approximated"],answer:"B",explanation:"'Approximately' is correct because an adverb is needed to modify the noun phrase 'five minutes,' indicating that the time is an estimate rather than an exact figure. 'Approximate' is wrong because it is an adjective (e.g., 'an approximate figure') or verb, and cannot directly modify a number or noun phrase in the adverb position before 'five minutes.' 'Approximation' is wrong because it is a noun meaning an estimate, and inserting a noun before 'five minutes' would create a grammatically incorrect structure without additional words. 'Approximated' is wrong because it is a past participle or past tense verb and cannot function as an adverb modifying a quantity.",category:"Word Form"},
  {id:"p5e2_85",question:"_____ you have any questions, please do not hesitate to contact us.",options:["A) Whether","B) Unless","C) Should","D) Whenever"],answer:"C",explanation:"'Should' is correct because 'should you have any questions' is a formal conditional inversion equivalent to 'if you should have any questions,' created by fronting the auxiliary 'should' and omitting 'if' — a structure common in professional correspondence. 'Whether' is wrong because 'whether you have any questions' introduces a yes/no choice or indirect question, not a conditional clause inviting the reader to reach out. 'Unless' is wrong because 'unless you have any questions' means 'except if you have questions,' which is the opposite of the intended open invitation to ask. 'Whenever' is wrong because it introduces a time clause meaning 'at any time that,' not a conditional invitation, and changes the meaning of the sentence.",category:"Grammar"},
  {id:"p5e2_86",question:"The printer runs _____ ink; could someone order a new cartridge?",options:["A) low in","B) low on","C) out of","D) both B and C"],answer:"D",explanation:"'Both B and C' is correct because 'running low on ink' (having very little remaining) and 'running out of ink' (having none left or nearly none) both naturally describe a printer that needs a new cartridge. 'Running low in ink' is wrong because the correct preposition after 'low' in this context is 'on,' not 'in'; 'low in' is used in different collocations (e.g., 'low in fat'). The two accepted options differ slightly: 'running low on' implies some ink remains but is nearly depleted, while 'running out of' implies depletion is imminent or has occurred.",category:"Vocabulary"},
  {id:"p5e2_87",question:"The supervisor _____ approval for all purchases over $500.",options:["A) must give","B) must be given","C) must grant","D) both A and C"],answer:"D",explanation:"'Both A and C' is correct because 'must give approval' and 'must grant approval' are both natural and grammatically correct expressions meaning the supervisor is required to authorize purchases exceeding $500. 'Must be given' is wrong because it makes the supervisor the receiver of approval rather than the person who gives it, reversing the intended meaning. 'Give approval' and 'grant approval' are both standard business collocations, with 'grant' being slightly more formal.",category:"Grammar"},
  {id:"p5e2_88",question:"The IT helpdesk is available _____ the clock.",options:["A) at","B) around","C) round","D) both B and C"],answer:"D",explanation:"'Both B and C' is correct because 'around the clock' and 'round the clock' are both established fixed expressions in English meaning continuously for 24 hours a day, 7 days a week. 'At the clock' is wrong because 'at the clock' is not an idiomatic expression; 'at' does not form a fixed phrase with 'the clock' in the sense of 24-hour availability. The two accepted options are regional variants: 'around the clock' is more common in American English, while 'round the clock' is more common in British English, but both are internationally understood.",category:"Vocabulary"},
  {id:"p5e2_89",question:"Please keep all correspondence _____ future reference.",options:["A) to","B) for","C) of","D) at"],answer:"B",explanation:"'For' is correct because 'for future reference' is a fixed prepositional phrase meaning to keep something so it can be consulted or used later, and 'for' is the only preposition that collocates naturally with 'future reference' in this expression. 'To' is wrong because 'to future reference' is not a standard expression in English; 'to' typically indicates direction or a recipient, not purpose in this context. 'Of' is wrong because 'of' is used to indicate belonging or composition (e.g., 'a matter of record') and does not form a natural phrase with 'future reference' here. 'At' is wrong because 'at future reference' is not an established English expression; 'at' indicates a specific point in time or place.",category:"Preposition"},
  {id:"p5e2_90",question:"The team _____ their best effort into the project and it showed.",options:["A) put","B) gave","C) poured","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'put their best effort into,' 'gave their best effort into,' and 'poured their best effort into' are all natural English expressions describing maximum commitment to a task. 'Put' is the most common and neutral collocate with 'effort into.' 'Gave' works in expressions like 'gave their all' or 'gave their best effort,' though 'gave effort into' is slightly less common. 'Poured' is metaphorical and vivid, suggesting an intense investment of energy into the project.",category:"Vocabulary"},
  {id:"p5e2_91",question:"The report must be _____ by 5 PM without exception.",options:["A) hand in","B) handed in","C) handing in","D) hand out"],answer:"B",explanation:"'Handed in' is correct because 'must be + past participle' forms the passive modal structure expressing a firm requirement, and 'handed in' is the past participle of the phrasal verb 'hand in' meaning to submit. 'Hand in' is wrong because the base form of the phrasal verb cannot follow 'must be'; the passive requires the past participle form. 'Handing in' is wrong because the present participle after 'must be' would form the passive continuous, which is grammatically unusual and does not express a simple submission requirement. 'Hand out' is wrong because it is a different phrasal verb meaning to distribute items to people, not to submit a report to a superior.",category:"Grammar"},
  {id:"p5e2_92",question:"The new hire showed great _____ on her first day.",options:["A) initiative","B) initiate","C) initiating","D) initiated"],answer:"A",explanation:"'Initiative' is correct because a noun is needed as the object of the verb 'showed,' and 'show initiative' is a standard business collocation meaning to act proactively without being told. 'Initiate' is wrong because it is a verb meaning to begin or introduce something, and a verb in its base form cannot serve as the object of 'showed.' 'Initiating' is wrong because as a gerund or present participle, it would awkwardly follow 'great' and does not collocate naturally with 'showed great ___.' 'Initiated' is wrong because it is a past tense verb or past participle and does not function as a noun object in this sentence.",category:"Vocabulary"},
  {id:"p5e2_93",question:"Parking is _____ outside the main building between 7 AM and 9 AM.",options:["A) restricted","B) restricting","C) restrict","D) restriction"],answer:"A",explanation:"'Restricted' is correct because 'parking is restricted' forms a passive construction where the past participle 'restricted' acts as a predicate adjective, describing the regulated status of parking in that area. 'Restricting' is wrong because the present participle would imply an active, ongoing action ('parking is restricting something'), which is semantically incorrect — the parking itself does not restrict anything. 'Restrict' is wrong because the base form of a verb cannot follow the linking verb 'is' as a predicate; only an adjective, noun, or participle can occupy this position. 'Restriction' is wrong because while it is a noun related to the concept, 'parking is restriction' is not grammatically correct; a predicate noun would require a different sentence structure.",category:"Grammar"},
  {id:"p5e2_94",question:"Could you please _____ the key points of the meeting for those who couldn't attend?",options:["A) summarize","B) recap","C) outline","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'summarize,' 'recap,' and 'outline' the key points are all valid and natural ways of providing a brief overview of meeting content for those who were absent. 'Summarize' means to give a concise account of the main points. 'Recap' means to recapitulate or go over the main points again, commonly used in business meetings. 'Outline' means to present the main features or points in a structured way, making all three options appropriate for this context.",category:"Vocabulary"},
  {id:"p5e2_95",question:"The team met _____ target for the third consecutive quarter.",options:["A) its","B) their","C) the","D) both A and B"],answer:"D",explanation:"'Both A and B' is correct because in English, collective nouns like 'team' can be treated as either singular (taking 'its') or plural (taking 'their'), depending on whether the speaker emphasizes the group as a unit or as individuals. 'Its' is standard in American English, where collective nouns are typically singular. 'Their' is standard in British English, where collective nouns are often treated as plural. 'The' is wrong because the definite article cannot serve as a possessive determiner; 'met the target' without a possessive leaves unclear whose target was met.",category:"Grammar"},
  {id:"p5e2_96",question:"The guest speaker has _____ 30 years of experience in international trade.",options:["A) more than","B) over","C) upwards of","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'more than 30 years,' 'over 30 years,' and 'upwards of 30 years' are all standard English expressions used to indicate that a quantity exceeds a given number. 'More than' is the most neutral and precise of the three. 'Over' is equally common and acceptable in formal and informal contexts. 'Upwards of' is slightly more formal and emphatic, often suggesting the number could be considerably higher.",category:"Vocabulary"},
  {id:"p5e2_97",question:"Please _____ your seat belt before the vehicle moves.",options:["A) fasten","B) wear","C) put on","D) both A and C"],answer:"D",explanation:"'Both A and C' is correct because 'fasten your seat belt' and 'put on your seat belt' are both natural and widely used English expressions for the action of securing a seat belt before a journey. 'Wear' is wrong in this specific context because while you 'wear' clothing and accessories, seat belts are specifically 'fastened' or 'put on,' not 'worn'; 'wear your seat belt' is not a standard collocation in safety announcements. The two correct options are the established collocations used in transportation safety instructions.",category:"Vocabulary"},
  {id:"p5e2_98",question:"The annual report _____ published on the company website every March.",options:["A) is","B) was","C) were","D) are"],answer:"A",explanation:"'Is' is correct because the singular subject 'the annual report' requires the singular present simple auxiliary 'is' to form the passive voice ('is published'), expressing a regular recurring action that happens every year. 'Was' is wrong because it forms the simple past passive, indicating a single completed past event rather than an ongoing annual routine. 'Were' is wrong because it is the plural past form and does not agree with the singular subject 'the annual report.' 'Are' is wrong because while it is a present plural auxiliary, it does not agree with the singular subject 'the annual report.'",category:"Grammar"},
  {id:"p5e2_99",question:"He _____ his job because the company offered him a better position.",options:["A) left","B) quit","C) resigned from","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'left his job,' 'quit his job,' and 'resigned from his job' are all valid English expressions for voluntarily ending employment, each with slightly different register. 'Left' is the most neutral and versatile. 'Quit' is more informal and direct, common in American English. 'Resigned from' is the most formal and is typically used in professional or official contexts when voluntarily departing from a position.",category:"Vocabulary"},
  {id:"p5e2_100",question:"The lunch break is _____ one hour every day.",options:["A) by","B) of","C) for","D) lasting"],answer:"C",explanation:"'For' is correct because 'for + time period' is the standard prepositional phrase expressing the duration of an event or period ('for one hour'). 'By' is wrong because 'by' before a time expression indicates a deadline ('by one hour' would mean before that time has passed), not the duration of a lunch break. 'Of' is wrong because 'of one hour' can describe composition (e.g., 'a break of one hour' in some formal contexts), but 'is of one hour' is not the natural or standard way to state the length of a break. 'Lasting' is wrong because it is a present participle and would need to form a different sentence structure (e.g., 'the lunch break, lasting one hour'); it cannot follow 'is' as a preposition in this slot.",category:"Preposition"},
  {id:"p5e2_101",question:"The building is _____ the subway station, just a five-minute walk.",options:["A) close to","B) near","C) next to","D) both A and B"],answer:"D",explanation:"'Both A and B' is correct because 'close to the subway station' and 'near the subway station' are both natural ways to express proximity, and both allow the additional clarification of 'a five-minute walk.' 'Next to' is wrong because it means immediately adjacent or right beside, implying physical contact or immediate adjacency rather than a five-minute walking distance. The two accepted options share the meaning of being within a short distance, without implying the building is literally beside the station.",category:"Preposition"},
  {id:"p5e2_102",question:"Please _____ this email to everyone in the distribution list.",options:["A) forward","B) send","C) copy","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'forward this email,' 'send this email,' and 'copy this email to everyone' are all valid instructions for distributing an email to a group. 'Forward' specifically means to pass on a received email to additional recipients. 'Send' is the most general term for transmitting an email. 'Copy' (or 'cc') means to include recipients so they receive the message, making all three options appropriate.",category:"Vocabulary"},
  {id:"p5e2_103",question:"The budget proposal is due _____ the end of the fiscal year.",options:["A) until","B) by","C) before","D) both B and C"],answer:"D",explanation:"'Both B and C' is correct because 'due by the end of the fiscal year' (meaning no later than that point) and 'due before the end of the fiscal year' (meaning at some point earlier than that time) are both grammatically correct deadline expressions. 'Until' is wrong because 'until' expresses a continuous state or action up to a certain point (e.g., 'wait until Friday'), not a submission deadline. The two accepted options reflect slightly different emphases: 'by' means at or before a deadline, while 'before' means strictly earlier than it.",category:"Preposition"},
  {id:"p5e2_104",question:"Her work has been _____ praised by the entire management team.",options:["A) high","B) highly","C) higher","D) highest"],answer:"B",explanation:"'Highly' is correct because an adverb is needed to modify the past participle 'praised,' and 'highly praised' is a standard collocation meaning praised to a great degree. 'High' is wrong because it is an adjective or position adverb (e.g., 'climb high'), not an adverb of degree that modifies past participles in this collocation. 'Higher' is wrong because it is the comparative form of the adjective 'high' and cannot serve as an adverb of degree modifying 'praised.' 'Highest' is wrong because it is the superlative form and cannot function as an adverb; moreover, 'highest praised' is not a standard English expression.",category:"Word Form"},
  {id:"p5e2_105",question:"The client was _____ satisfied with the service provided.",options:["A) complete","B) completely","C) completion","D) completed"],answer:"B",explanation:"'Completely' is correct because an adverb of degree is needed to modify the adjective 'satisfied,' indicating that the client's satisfaction was total ('completely satisfied'). 'Complete' is wrong because it is an adjective that modifies nouns (e.g., 'a complete success'), not an adverb that modifies other adjectives like 'satisfied.' 'Completion' is wrong because it is a noun referring to the state of being finished, and a noun cannot serve as an adverb modifying an adjective. 'Completed' is wrong because it is a past participle or adjective, and 'completed satisfied' is not a grammatical adverb-adjective combination.",category:"Word Form"},
  {id:"p5e2_106",question:"The conference call _____ at 10 AM and ended at 11:30 AM.",options:["A) starts","B) started","C) has started","D) is starting"],answer:"B",explanation:"'Started' is correct because the simple past tense describes a completed past action, and the conjunction 'and ended' confirms that both events are narrated as finished past occurrences. 'Starts' is wrong because the present simple describes current habits or scheduled future events, not a completed call from the past. 'Has started' is wrong because the present perfect is used for past actions with present relevance, but the sentence gives specific past times ('at 10 AM' and 'ended'), which require the simple past. 'Is starting' is wrong because the present continuous describes an action in progress now or an imminent future plan, neither of which fits a call that has clearly already started and ended.",category:"Grammar"},
  {id:"p5e2_107",question:"She _____ the company for 20 years before retiring last year.",options:["A) has worked","B) is working","C) had worked","D) was working"],answer:"C",explanation:"'Had worked' is correct because the past perfect is used to describe an action that was completed before another action in the past — here, working for 20 years was completed before the past event of retiring. 'Has worked' is wrong because the present perfect describes a past action with relevance to the present, but since she retired ('last year'), the employment has fully ended and is not relevant to now. 'Is working' is wrong because the present continuous describes an action happening now, but she retired, so she is no longer working for the company. 'Was working' is wrong because the past continuous describes an action in progress at a specific moment in the past, not a completed 20-year period that preceded retirement.",category:"Grammar"},
  {id:"p5e2_108",question:"The training room is _____ for groups of up to 30 participants.",options:["A) capable","B) suitable","C) able","D) fitting"],answer:"B",explanation:"'Suitable' is correct because 'suitable for' is the fixed prepositional collocation meaning appropriate or right for a particular purpose or group size, and 'suitable for groups of up to 30' is standard business language. 'Capable' is wrong because 'capable of' is used for living beings or machines that can perform actions (e.g., 'capable of holding 30 people'), and while grammatically possible, 'capable for' is not the standard construction. 'Able' is wrong because 'able' requires a subject with agency (a person or device) and the structure 'able to + infinitive,' not 'able for a group.' 'Fitting' is wrong because while it can mean appropriate as an adjective in some contexts (e.g., 'a fitting tribute'), 'fitting for groups' is not the standard collocation used to describe room capacity.",category:"Vocabulary"},
  {id:"p5e2_109",question:"We are _____ a solution to the supply chain issue.",options:["A) working on","B) working at","C) working for","D) working by"],answer:"A",explanation:"'Working on' is correct because 'work on something' is the standard phrasal verb meaning to actively spend time and effort trying to solve or develop something, as in 'working on a solution.' 'Working at' is wrong because 'work at' typically refers to a place of employment (e.g., 'working at the factory') or working hard in a general sense, but does not collocate naturally with 'a solution.' 'Working for' is wrong because 'work for' means to be employed by someone or to strive toward a goal (e.g., 'working for justice'), but not to actively develop a specific solution. 'Working by' is wrong because 'work by' refers to a method used (e.g., 'working by the guidelines') and does not collocate with 'a solution' in this context.",category:"Vocabulary"},
  {id:"p5e2_110",question:"The shop will be closed _____ renovation from Monday to Wednesday.",options:["A) for","B) during","C) throughout","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'closed for renovation' (indicating the reason/purpose of closure), 'closed during renovation' (indicating a time period), and 'closed throughout renovation' (emphasizing the entire duration) are all grammatically correct and contextually natural. 'For' presents the renovation as the reason or purpose of the closure. 'During' situates the closure within the time frame of the renovation. 'Throughout' emphasizes that the closure covers the entire renovation period without interruption.",category:"Preposition"},
  {id:"p5e2_111",question:"The proposal needs to be _____ before we submit it to the board.",options:["A) proofread","B) polished","C) refined","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'proofread,' 'polished,' and 'refined' all describe improving a document before submission, though with different focuses. 'Proofread' means to check for errors in spelling, grammar, and punctuation. 'Polished' means to improve the overall quality and presentation so it appears professional. 'Refined' means to make subtle improvements to the content, language, or structure, making all three valid in the context of preparing a proposal.",category:"Vocabulary"},
  {id:"p5e2_112",question:"There is _____ need to attend if you have already reviewed the materials.",options:["A) no","B) not any","C) not a","D) both A and B"],answer:"D",explanation:"'Both A and B' is correct because 'there is no need' and 'there is not any need' are both grammatically correct ways to say that attending is unnecessary, with 'no' being more concise and 'not any' being slightly more emphatic. 'Not a need' is wrong because 'not a' negates a singular countable noun but does not form a natural idiomatic English expression in this structure; 'there is not a need' is unusual and sounds awkward compared to the standard 'no need.' The two accepted options are standard negation structures with 'there is,' both conveying the same meaning clearly.",category:"Grammar"},
  {id:"p5e2_113",question:"The company _____ provide reimbursement for travel-related expenses.",options:["A) does","B) will","C) can","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'does provide' (emphasizing that it currently and factually does), 'will provide' (indicating future provision), and 'can provide' (indicating it is possible or permitted) are all grammatically correct depending on context and emphasis. 'Does provide' is an emphatic present simple used to confirm a policy. 'Will provide' indicates future commitment. 'Can provide' indicates ability or authorization — all three are valid in different policy communication contexts.",category:"Grammar"},
  {id:"p5e2_114",question:"The technician _____ the issue in less than an hour.",options:["A) fixing","B) fixed","C) was fixing","D) has fixed"],answer:"B",explanation:"'Fixed' is correct because the simple past tense describes a completed action at a specific time in the past, and 'in less than an hour' is a time expression indicating the action has finished. 'Fixing' is wrong because the present participle cannot serve as the main verb without an auxiliary (e.g., 'is fixing'), and 'in less than an hour' signals completion, not an ongoing action. 'Was fixing' is wrong because the past continuous describes an action in progress at a past moment, not a completed result; 'was fixing in less than an hour' would be contradictory. 'Has fixed' is wrong because while the present perfect is possible in some contexts, 'in less than an hour' as a duration of a completed action is more naturally expressed with the simple past in standard business English.",category:"Grammar"},
  {id:"p5e2_115",question:"She was the _____ person to arrive at the meeting.",options:["A) later","B) lately","C) last","D) latest"],answer:"C",explanation:"'Last' is correct because 'the last person to arrive' means the final person in a sequence — no one arrived after her — and 'last' functions as an ordinal adjective in superlative position here. 'Later' is wrong because it is the comparative form of 'late,' meaning at a time after another point, and 'the later person to arrive' implies a comparison between two people rather than a final position in a sequence. 'Lately' is wrong because it is an adverb meaning recently, and an adverb cannot modify the noun 'person' in this position. 'Latest' is wrong because 'latest' means most recent in time (e.g., 'the latest model') rather than final in sequence; 'the latest person to arrive' would awkwardly imply she is the most recent arrival, not the very last one.",category:"Vocabulary"},
  {id:"p5e2_116",question:"The promotion was given _____ someone with more experience.",options:["A) for","B) to","C) at","D) toward"],answer:"B",explanation:"'To' is correct because 'give something to someone' is the standard ditransitive structure where 'to' introduces the indirect object — the recipient of the promotion. 'For' is wrong because 'given for someone' would express purpose or benefit in a general sense rather than specifying the recipient of the promotion. 'At' is wrong because 'at' indicates direction toward a target or a point in time, not the recipient of something given. 'Toward' is wrong because it indicates movement in a direction and is not used to introduce the recipient of something that is formally conferred.",category:"Preposition"},
  {id:"p5e2_117",question:"The results _____ our expectations by a wide margin.",options:["A) exceed","B) exceeded","C) were exceeding","D) are exceeded"],answer:"B",explanation:"'Exceeded' is correct because the simple past tense describes a completed event — the results surpassed expectations at a specific past time, confirmed by the past context of the sentence. 'Exceed' is wrong because the present simple describes habitual or current facts, not a completed past event involving specific results. 'Were exceeding' is wrong because the past continuous describes an ongoing process at a past moment, but 'by a wide margin' indicates a concluded comparison, not an in-progress action. 'Are exceeded' is wrong because it is present passive, meaning expectations surpass the results (reversing subject and object), which is the opposite of the intended meaning.",category:"Grammar"},
  {id:"p5e2_118",question:"The new catalog is available _____ free of charge.",options:["A) from","B) for","C) at","D) as"],answer:"B",explanation:"'For' is correct because 'available for free' or 'free of charge' uses 'for' as the preposition indicating a cost (or lack thereof), and 'available for free of charge' combines both common expressions. 'From' is wrong because 'available from' indicates a source or starting point (e.g., 'available from our website'), not cost. 'At' is wrong because 'at' before a price indicates a specific cost (e.g., 'available at $10'), so 'at free of charge' would be redundant and ungrammatical. 'As' is wrong because 'as free of charge' would incorrectly use 'as' to compare or equate, rather than to express cost.",category:"Preposition"},
  {id:"p5e2_119",question:"All applications must be _____ before the deadline.",options:["A) submit","B) submitting","C) submitted","D) submits"],answer:"C",explanation:"'Submitted' is correct because 'must be + past participle' forms the passive modal construction expressing a requirement, and 'submitted' is the past participle of 'submit' needed to complete this structure ('must be submitted'). 'Submit' is wrong because the base form cannot follow 'must be'; the passive voice requires a past participle, not a base infinitive. 'Submitting' is wrong because the present participle after 'must be' would form the passive continuous, which is grammatically unusual and does not express a clear deadline requirement. 'Submits' is wrong because the third-person singular present active form cannot follow 'must be' to form a passive construction.",category:"Grammar"},
  {id:"p5e2_120",question:"The department had a _____ meeting to discuss the quarterly results.",options:["A) brief","B) shortly","C) short","D) both A and C"],answer:"D",explanation:"'Both A and C' is correct because 'a brief meeting' and 'a short meeting' are both natural and standard English expressions meaning a meeting of limited duration. 'Shortly' is wrong because it is an adverb meaning soon or in a short while (e.g., 'we will meet shortly'), and an adverb cannot serve as a modifier for the noun 'meeting' in this attributive position. The two correct options are near-synonyms: 'brief' is slightly more formal and commonly used in business writing, while 'short' is more general and informal.",category:"Vocabulary"},
  {id:"p5e2_121",question:"She works in the _____ department and handles all invoices.",options:["A) account","B) accounts","C) accounting","D) both B and C"],answer:"D",explanation:"'Both B and C' is correct because 'accounts department' (the department that manages financial accounts, common in British English) and 'accounting department' (common in American English) are both standard terms for the department that handles financial records and invoices. 'Account' as a singular noun modifier is wrong because the standard compound nouns are 'accounts' (plural) or 'accounting' (gerund), not the singular 'account' on its own in this context. The two accepted options reflect regional variation in business English terminology.",category:"Vocabulary"},
  {id:"p5e2_122",question:"Please let me know _____ you can attend the session.",options:["A) when","B) if","C) whether","D) both B and C"],answer:"D",explanation:"'Both B and C' is correct because 'let me know if you can attend' and 'let me know whether you can attend' are both grammatically correct indirect yes/no questions embedded in a polite request, and 'if' and 'whether' are interchangeable in this structure. 'When' is wrong because 'let me know when you can attend' presupposes that the person will attend and asks for the time, not whether they will attend — this changes the meaning significantly. The two correct options both ask about the possibility or likelihood of attendance without presupposing the answer.",category:"Grammar"},
  {id:"p5e2_123",question:"The supplier offered a _____ of five percent for early payment.",options:["A) discount","B) rebate","C) reduction","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'a discount of five percent,' 'a rebate of five percent,' and 'a reduction of five percent' all describe a lowering of the price by five percent in exchange for early payment. 'Discount' is the most common term for a price reduction offered at the point of sale. 'Rebate' refers to a partial refund given after payment, often as an incentive. 'Reduction' is the most general term for any lowering of price — all three are valid in this financial context.",category:"Vocabulary"},
  {id:"p5e2_124",question:"The new receptionist _____ visitors with a warm welcome every day.",options:["A) greet","B) greets","C) greeted","D) greeting"],answer:"B",explanation:"'Greets' is correct because the third-person singular subject 'the new receptionist' requires the -s form of the verb in the present simple tense, used here to describe a habitual daily action. 'Greet' is wrong because the base form is used with I/you/we/they, not with the singular third-person subject 'the new receptionist.' 'Greeted' is wrong because the simple past describes a completed past event, whereas 'every day' signals a current routine requiring the present simple. 'Greeting' is wrong because the present participle cannot function as the main verb without an auxiliary such as 'is.'",category:"Grammar"},
  {id:"p5e2_125",question:"He forgot _____ the meeting invitation, so nobody received the calendar event.",options:["A) to send","B) sending","C) send","D) to sending"],answer:"A",explanation:"'Forgot to send' is correct because when 'forget' is followed by 'to + infinitive,' it means the person failed to do something they intended — here, he did not send the invitation because he forgot to do so. 'Forgot sending' is wrong because 'forget + gerund' means to have no memory of an action that was already performed (e.g., 'forgot sending it' implies he sent it but cannot remember doing so), which contradicts the consequence of nobody receiving the event. 'Forgot send' is wrong because the base form alone cannot follow 'forgot'; either the infinitive 'to send' or the gerund 'sending' is required. 'Forgot to sending' is wrong because 'to' is always followed by the base infinitive, not the gerund; 'to sending' violates the infinitive structure.",category:"Grammar"},
  {id:"p5e2_126",question:"I remember _____ this client last year at the trade fair.",options:["A) to meet","B) meeting","C) meet","D) met"],answer:"B",explanation:"'Remember meeting' is correct because when 'remember' is followed by a gerund, it means to have a memory of something that already happened — in this case, recalling the past event of meeting the client. 'Remember to meet' is wrong because 'remember + to + infinitive' means to not forget to do a future action (e.g., 'remember to call him tomorrow'), which is the opposite meaning from recalling a past event. 'Remember meet' is wrong because the base form alone cannot follow 'remember'; a gerund or infinitive is required. 'Remember met' is wrong because 'met' is a past tense verb or past participle and cannot follow 'remember' directly in this grammatical slot.",category:"Grammar"},
  {id:"p5e2_127",question:"They stopped _____ new staff due to budget constraints.",options:["A) hire","B) to hire","C) hiring","D) hired"],answer:"C",explanation:"'Stopped hiring' is correct because 'stop + gerund' means to cease an activity that was previously occurring — they were hiring staff and then discontinued the process. 'Stop hire' is wrong because the base form cannot follow 'stopped'; a gerund or infinitive is required. 'Stopped to hire' is wrong because 'stop + to + infinitive' means to pause in order to do something else (e.g., 'stopped to take a break'), not to cease an activity. 'Stopped hired' is wrong because a past tense verb or past participle cannot follow 'stopped' in this grammatical structure.",category:"Grammar"},
  {id:"p5e2_128",question:"The manager tried _____ the client, but the call kept dropping.",options:["A) to call","B) calling","C) call","D) both A and B"],answer:"D",explanation:"'Both A and B' is correct because 'tried to call' (made an attempt to call, implying some difficulty in connecting) and 'tried calling' (experimented with the method of calling) are both grammatically correct, with slightly different nuances. 'Try + to + infinitive' means to make an effort to do something, while 'try + gerund' means to experiment with doing something as a potential solution — both apply when a call keeps dropping. 'Tried call' is wrong because the base form alone cannot follow 'tried' in this construction; either the infinitive or gerund is required.",category:"Grammar"},
  {id:"p5e2_129",question:"She regrets _____ the job offer; the company grew significantly.",options:["A) to reject","B) rejecting","C) rejected","D) reject"],answer:"B",explanation:"'Regrets rejecting' is correct because 'regret + gerund' means to feel sorry about something that has already happened — she is looking back with regret at the past action of rejecting the offer. 'Regrets to reject' is wrong because 'regret + to + infinitive' is used as a polite formula for delivering bad news in the present (e.g., 'I regret to inform you'), not for expressing sorrow about a past personal decision. 'Regrets rejected' is wrong because a past tense verb cannot follow 'regrets' in this grammatical position. 'Regrets reject' is wrong because the base form cannot follow 'regrets'; a gerund or infinitive is required.",category:"Grammar"},
  {id:"p5e2_130",question:"He went on _____ even after everyone else had finished.",options:["A) talk","B) talking","C) to talk","D) talked"],answer:"B",explanation:"'Went on talking' is correct because 'go on + gerund' means to continue doing the same activity without stopping, which matches the meaning that he kept talking after others finished. 'Went on talk' is wrong because the base form cannot follow 'went on'; a gerund or infinitive is required. 'Went on to talk' is wrong because 'go on + to + infinitive' means to move on to a new or next activity (e.g., 'went on to discuss another topic'), not to continue the same activity. 'Went on talked' is wrong because the past tense form cannot follow 'went on' in this grammatical construction.",category:"Grammar"},
  {id:"p5e2_131",question:"The proposal needs more work; _____, I suggest we revise it before submitting.",options:["A) therefore","B) however","C) although","D) despite"],answer:"A",explanation:"'Therefore' is correct because it is a result connector that introduces a logical conclusion drawn from the preceding statement — since the proposal needs more work, the natural conclusion is to suggest revision. 'However' is wrong because it introduces a contrast or contradiction, and there is no contrasting idea between needing more work and suggesting revision. 'Although' is wrong because it is a subordinating conjunction introducing a concessive clause and cannot stand alone between two independent clauses separated by a semicolon. 'Despite' is wrong because it is a preposition that must be followed by a noun phrase or gerund, not an independent clause.",category:"Connector"},
  {id:"p5e2_132",question:"Sales were below target; _____, management remained optimistic.",options:["A) therefore","B) furthermore","C) however","D) since"],answer:"C",explanation:"'However' is correct because it is a contrast connector that introduces a contrasting idea — despite poor sales, management was optimistic, which is an unexpected or contrasting outcome. 'Therefore' is wrong because it signals a logical result or conclusion, but management being optimistic is not a logical result of sales being below target; it is a contrast to it. 'Furthermore' is wrong because it adds supporting information to a previous point, but optimism despite poor sales is not additional supporting information — it is a contrasting one. 'Since' is wrong because it introduces a reason or a time clause and cannot stand alone between two independent clauses joined by a semicolon in this connecting role.",category:"Connector"},
  {id:"p5e2_133",question:"The new policy reduces costs; _____, it improves efficiency.",options:["A) however","B) furthermore","C) despite","D) unless"],answer:"B",explanation:"'Furthermore' is correct because it is an additive connector used to introduce another supporting point, indicating that the policy has an additional benefit beyond reducing costs. 'However' is wrong because it signals contrast, but reducing costs and improving efficiency are both positive outcomes — there is no contrast between them. 'Despite' is wrong because it is a preposition requiring a noun phrase or gerund, and cannot connect two independent clauses in this position. 'Unless' is wrong because it is a conditional subordinating conjunction meaning 'except if,' which introduces a condition rather than an additional benefit.",category:"Connector"},
  {id:"p5e2_134",question:"We have met the deadline; _____, all deliverables have been approved.",options:["A) moreover","B) in addition","C) furthermore","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'moreover,' 'in addition,' and 'furthermore' are all additive discourse connectors that introduce additional positive information, and each can naturally follow the statement about meeting a deadline to add that deliverables were also approved. 'Moreover' adds information with slight emphasis, implying the second point is even more significant. 'In addition' neutrally introduces an extra point. 'Furthermore' also adds information, often used in formal writing to build an argument — all three are interchangeable here.",category:"Connector"},
  {id:"p5e2_135",question:"The client was unhappy; _____, we offered a full refund.",options:["A) consequently","B) as a result","C) therefore","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'consequently,' 'as a result,' and 'therefore' are all result connectors that introduce a logical consequence — the client's unhappiness led to the decision to offer a full refund. 'Consequently' is slightly more formal and often used in written business communication. 'As a result' is the most explicit in showing cause and effect. 'Therefore' is the most concise and widely used in formal and informal contexts — all three connect the cause (unhappy client) to the effect (refund) equally well.",category:"Connector"},
  {id:"p5e2_136",question:"He works full-time _____ studying for his MBA.",options:["A) while","B) during","C) as","D) both A and C"],answer:"A",explanation:"'While' is correct because 'while + gerund' ('while studying') is the standard structure for expressing two simultaneous ongoing actions with the same subject, and it naturally introduces the parallel activity of studying for an MBA. 'During' is wrong because 'during' is a preposition requiring a noun phrase (e.g., 'during his MBA studies'), not a gerund phrase directly. 'As' is wrong in this structure because 'as' as a temporal conjunction requires a full finite clause (e.g., 'as he studies for his MBA'), not a bare gerund; 'as studying' is ungrammatical in standard English. 'Both A and C' is wrong because option C ('as') cannot precede a gerund in a temporal clause, so the combined option is also incorrect.",category:"Grammar"},
  {id:"p5e2_137",question:"_____ arriving at the hotel, please call the conference organizer.",options:["A) After","B) Upon","C) Following","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'after arriving,' 'upon arriving,' and 'following arriving' (or more commonly 'following your arrival') are all grammatically acceptable ways to sequence the actions. 'After arriving' is the most common and neutral expression. 'Upon arriving' is a more formal expression meaning immediately after arriving. 'Following arriving' (or 'following arrival') is used in formal written communication to indicate the subsequent action — all three are valid instructions.",category:"Grammar"},
  {id:"p5e2_138",question:"The team finished ahead of schedule, _____ saved significant costs.",options:["A) which","B) that","C) what","D) how"],answer:"A",explanation:"'Which' is correct because a non-defining (non-restrictive) relative clause is needed here to refer back to the entire preceding idea ('finishing ahead of schedule'), and 'which' is the required pronoun for such clauses referring to a whole clause or idea. 'That' is wrong because 'that' is used in defining relative clauses (without commas) and cannot introduce a non-defining clause referring to an entire preceding statement. 'What' is wrong because 'what' in a relative clause means 'the thing that' and introduces a noun clause, not a clause modifying a preceding idea. 'How' is wrong because it introduces an indirect question about manner (e.g., 'I don't know how') and cannot serve as a relative pronoun in this structure.",category:"Grammar"},
  {id:"p5e2_139",question:"The employee _____ complained repeatedly was eventually transferred.",options:["A) who","B) whom","C) whose","D) which"],answer:"A",explanation:"'Who' is correct because the relative pronoun here refers to a person ('the employee') and functions as the subject of the relative clause ('who complained'), requiring the subject form 'who.' 'Whom' is wrong because it is the object form of the relative pronoun for people (e.g., 'the employee whom the manager contacted'), used when the pronoun is the object of the clause, not the subject. 'Whose' is wrong because it is the possessive relative pronoun for people (e.g., 'the employee whose performance declined'), not the subject pronoun. 'Which' is wrong because it refers to things, animals, or clauses, not to people such as an employee.",category:"Grammar"},
  {id:"p5e2_140",question:"The report, _____ I sent you last week, contains all the key figures.",options:["A) that","B) which","C) what","D) who"],answer:"B",explanation:"'Which' is correct because the commas around the clause signal a non-defining (non-restrictive) relative clause, and non-defining clauses must use 'which' for things, not 'that.' 'That' is wrong because defining relative clauses (no commas) use 'that,' but the presence of commas here requires 'which' — 'that' cannot introduce a non-defining clause. 'What' is wrong because 'what' introduces noun clauses (e.g., 'I don't know what you sent'), not relative clauses modifying a previously mentioned noun. 'Who' is wrong because 'who' is the relative pronoun for people, while 'the report' is a thing requiring 'which.'",category:"Grammar"},
  {id:"p5e2_141",question:"The team leader _____ email address is on the board will answer your questions.",options:["A) which","B) who","C) whose","D) whom"],answer:"C",explanation:"'Whose' is correct because it is the possessive relative pronoun, used here to show that the email address belongs to the team leader ('the team leader whose email address is on the board'). 'Which' is wrong because it is a relative pronoun for things, not for people, and it does not convey possession — 'which email address' would need a different structure. 'Who' is wrong because it is the subject form for people and cannot express possession; 'who email address' is ungrammatical. 'Whom' is wrong because it is the object form for people (e.g., 'the leader whom you should contact') and does not express possession.",category:"Grammar"},
  {id:"p5e2_142",question:"The building _____ we hold our training sessions has excellent facilities.",options:["A) which","B) where","C) that","D) both A and B"],answer:"D",explanation:"'Both A and B' is correct because 'the building which we hold our training sessions in' (with the preposition 'in' at the end) and 'the building where we hold our training sessions' are both grammatically correct relative clause structures, with 'where' functioning as a relative adverb replacing 'in which.' 'Which' or 'that' can introduce a defining clause with the preposition 'in' implied, while 'where' is the natural relative adverb for place. 'That' is wrong as the sole answer because the question targets both the relative pronoun 'which' and the relative adverb 'where' as correct options; selecting only C would miss the equally valid option A. 'How' is not a valid relative pronoun or adverb for referring to a building.",category:"Grammar"},
  {id:"p5e2_143",question:"That was the year _____ the company celebrated its 50th anniversary.",options:["A) which","B) where","C) when","D) that"],answer:"C",explanation:"'When' is correct because it is the relative adverb used to refer to a time expression ('the year'), replacing 'in which' and introducing a clause that describes what happened during that time. 'Which' is wrong because while 'the year in which' is grammatically correct, 'which' alone (without 'in') would leave the preposition missing and is not the most natural choice when a relative adverb is available. 'Where' is wrong because it is a relative adverb for places, not time expressions like 'the year.' 'That' is wrong because while 'that' can substitute for 'which' in defining clauses with nouns, 'the year that' sounds unnatural compared to 'the year when' in this context.",category:"Grammar"},
  {id:"p5e2_144",question:"Please send the parcel to the address _____ I provided earlier.",options:["A) that","B) which","C) where","D) both A and B"],answer:"D",explanation:"'Both A and B' is correct because in a defining relative clause, both 'that' and 'which' can be used to refer to a thing (the address), making 'the address that I provided' and 'the address which I provided' both grammatically correct. 'Where' is wrong because 'where' is a relative adverb referring to a location where actions occur (e.g., 'the address where I used to live'), but in this sentence the clause refers to which address was provided, not to an action occurring at the address. The two accepted options reflect the flexibility of defining relative clauses in English, where 'that' and 'which' are interchangeable for things.",category:"Grammar"},
  {id:"p5e2_145",question:"_____ by the client's praise, the team redoubled their efforts.",options:["A) Encouraged","B) Encouraging","C) To encourage","D) Encouragement"],answer:"A",explanation:"'Encouraged' is correct because the sentence requires a passive participial clause ('encouraged by the client's praise') that modifies the subject 'the team,' indicating they were the recipients of the praise. 'Encouraging' is wrong because the active present participle would mean the team was encouraging something or someone else, not that they were encouraged by praise. 'To encourage' is wrong because a 'to + infinitive' clause here would express purpose (the team redoubled efforts in order to encourage) rather than the reason for their effort. 'Encouragement' is wrong because it is a noun and cannot introduce a participial clause that modifies the subject of the main clause.",category:"Grammar"},
  {id:"p5e2_146",question:"_____ the new pricing structure, the marketing team updated all materials.",options:["A) Announcing","B) Having announced","C) Being announced","D) Announced"],answer:"B",explanation:"'Having announced' is correct because the perfect participle 'having + past participle' is used when the action in the participial clause was completed before the action in the main clause — the announcement of the pricing structure was completed before the team updated the materials. 'Announcing' is wrong because the present participle implies the two actions are simultaneous, but the announcement logically preceded the updating of materials. 'Being announced' is wrong because it is a passive progressive participle, implying the pricing structure was being announced at the same time, which does not reflect the sequence. 'Announced' is wrong because the past participle alone as a participial phrase would make the marketing team the recipient of the announcement (passive), when the team is actually the one that announced it.",category:"Grammar"},
  {id:"p5e2_147",question:"_____ with multiple complaints, the manager arranged an urgent meeting.",options:["A) Facing","B) Faced","C) To face","D) Having faced"],answer:"B",explanation:"'Faced' is correct because 'faced with + noun' is a fixed passive participial expression meaning confronted by or dealing with a challenging situation, and it functions as a reduced passive clause modifying the subject 'the manager.' 'Facing' is wrong because while 'facing with' sounds plausible, the correct idiomatic form is 'faced with' — 'facing' without 'with' can mean confronting something, but 'facing with multiple complaints' is not standard. 'To face' is wrong because an infinitive phrase here would suggest purpose (the manager arranged the meeting in order to face complaints), which alters the intended meaning. 'Having faced' is wrong because it suggests the complaints were fully dealt with before the meeting, but the arrangement of the meeting is the response to the complaints, not what comes after resolving them.",category:"Grammar"},
  {id:"p5e2_148",question:"The client called to confirm _____ the order had been shipped.",options:["A) if","B) whether","C) that","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'confirm if,' 'confirm whether,' and 'confirm that' are all grammatically valid structures after the verb 'confirm,' each with a slightly different nuance. 'Confirm that' asserts the fact being verified ('confirm that it was shipped'). 'Confirm if/whether' introduces an indirect yes/no question, asking whether the shipping took place. All three completions produce natural sentences in business English.",category:"Grammar"},
  {id:"p5e2_149",question:"Please advise _____ you prefer the Monday or Tuesday delivery slot.",options:["A) if","B) whether","C) both A and B","D) that"],answer:"C",explanation:"'Both A and B' is correct because 'advise if you prefer' and 'advise whether you prefer' are both grammatically correct ways to introduce an indirect yes/no question asking for the recipient's preference between two options. 'That' is wrong because 'advise that' introduces a statement of fact or a recommendation (e.g., 'I advise that you choose Tuesday'), not an indirect question about preference. The two correct options ('if' and 'whether') are interchangeable when introducing embedded yes/no questions, though 'whether' is considered slightly more formal.",category:"Grammar"},
  {id:"p5e2_150",question:"The manager wasn't sure _____ to handle the sensitive complaint.",options:["A) what","B) how","C) when","D) both A and B"],answer:"B",explanation:"'How' is correct because 'wasn't sure how to handle' is the standard structure for expressing uncertainty about the method or manner of doing something — the manager did not know the best approach. 'What' is wrong because 'wasn't sure what to handle' would express uncertainty about which thing to deal with, not how to deal with a specific thing that has already been identified ('the sensitive complaint'). 'When' is wrong because 'wasn't sure when to handle' expresses uncertainty about timing, not about the manner of handling. 'Both A and B' is wrong because 'what' changes the meaning significantly in this context, so only 'how' accurately reflects the intended uncertainty about method.",category:"Grammar"},
  {id:"p5e2_151",question:"We couldn't decide _____ to hold the event indoors or outdoors.",options:["A) whether","B) if","C) how","D) what"],answer:"A",explanation:"'Whether' is correct because when a decision involves a choice between two alternatives, 'whether...or' is the required structure ('whether to hold it indoors or outdoors'), and 'whether' is the conjunction used in infinitive clauses expressing a binary choice. 'If' is wrong because 'if' cannot be used before an infinitive in indirect questions — 'couldn't decide if to hold' is ungrammatical in standard English; 'whether' is required with infinitives. 'How' is wrong because it expresses manner or method (e.g., 'couldn't decide how to set it up'), not a binary choice between two options. 'What' is wrong because 'couldn't decide what to hold' would question the nature of the event, not its location.",category:"Grammar"},
  {id:"p5e2_152",question:"He told me _____ to worry; the issue was already resolved.",options:["A) don't","B) not","C) no","D) didn't"],answer:"B",explanation:"'Not' is correct because in reported speech, an imperative ('Don't worry') is converted to an infinitive with 'not to' ('told me not to worry'), which is the standard structure for reported negative commands and instructions. 'Don't' is wrong because 'don't' is used in direct speech imperatives and cannot be used in the reported speech construction 'told me don't to worry.' 'No' is wrong because 'no' is a determiner or interjection and does not function as a negative in the infinitive clause 'told me ___ to worry.' 'Didn't' is wrong because it is a past tense auxiliary for negating a past action, not a particle used in reported imperative structures.",category:"Grammar"},
  {id:"p5e2_153",question:"She said that she _____ the report the following morning.",options:["A) will submit","B) would submit","C) submits","D) has submitted"],answer:"B",explanation:"'Would submit' is correct because in reported speech, when the reporting verb ('said') is in the past tense, 'will' shifts back to 'would' in accordance with the sequence of tenses rule ('will submit' becomes 'would submit'). 'Will submit' is wrong because it is the direct speech form; after a past reporting verb, 'will' must shift to 'would' in reported speech. 'Submits' is wrong because the present simple in reported speech after a past reporting verb would need to shift to past simple ('submitted'), not remain in the present. 'Has submitted' is wrong because the present perfect in reported speech after a past reporting verb shifts to the past perfect ('had submitted').",category:"Grammar"},
  {id:"p5e2_154",question:"He told me he _____ the job offer earlier that week.",options:["A) accepted","B) has accepted","C) had accepted","D) would accept"],answer:"C",explanation:"'Had accepted' is correct because when reporting a past action in reported speech after a past reporting verb ('told'), the simple past ('accepted') shifts to the past perfect ('had accepted') to show that the acceptance occurred before the telling. 'Accepted' is wrong because while acceptable in informal speech, formal reported speech requires the past perfect when reporting a past action after a past tense reporting verb. 'Has accepted' is wrong because the present perfect becomes the past perfect in reported speech, not retains the present perfect form. 'Would accept' is wrong because 'would' in reported speech corresponds to 'will' in direct speech, implying a future action, not a past action that had already occurred.",category:"Grammar"},
  {id:"p5e2_155",question:"The manager asked if I _____ available for a call the next day.",options:["A) am","B) was","C) were","D) both B and C"],answer:"D",explanation:"'Both B and C' is correct because in reported speech after a past tense reporting verb ('asked'), 'are' shifts to either 'was' (standard backshift) or 'were' (subjunctive mood, often used in formal or hypothetical contexts), making both grammatically acceptable. 'Am' is wrong because the present tense 'am' does not apply after a past tense reporting verb in reported speech; it must shift to a past form. The two accepted options reflect that both the simple past 'was' and the subjunctive 'were' are used in formal and informal reported questions in English.",category:"Grammar"},
  {id:"p5e2_156",question:"She announced that the company _____ a new product that month.",options:["A) launched","B) was launching","C) had launched","D) both B and C"],answer:"D",explanation:"'Both B and C' is correct because 'was launching' (describing a launch in progress during that month — the action was ongoing at the time of the announcement) and 'had launched' (describing a launch already completed before the announcement was made) are both grammatically valid reported speech forms. 'Launched' is wrong because although a simple past backshift is possible in reported speech, 'that month' implies a time concurrent with the announcement, making the progressive or perfect forms more precise and natural here. 'Would launch' is wrong because it would describe a future action relative to the announcement, but 'that month' implies the launch was occurring or had occurred during the same period, not afterward.",category:"Grammar"},
  {id:"p5e2_157",question:"The technician _____ the printer is working fine now.",options:["A) tells","B) said","C) reported","D) confirmed"],answer:"D",explanation:"'Confirmed' is correct because 'confirm' means to verify or establish with certainty that something is the case, which is the most precise word for a technician verifying the operational status of a printer after a check. 'Tells' is wrong because 'tells' is present tense and does not fit the past-event context, and it also lacks the nuance of verification — it simply conveys information rather than confirming a finding. 'Said' is wrong because 'said' merely reports what someone stated without implying any verification or technical checking of the printer. 'Reported' is wrong because it implies filing a formal report to a superior rather than directly verifying and communicating a technical finding, making it an imprecise choice for this context.",category:"Vocabulary"},
  {id:"p5e2_158",question:"He proposed _____ the budget for the next fiscal year.",options:["A) to increase","B) increasing","C) an increase in","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'proposed to increase,' 'proposed increasing,' and 'proposed an increase in' the budget are all grammatically correct and commonly used structures after the verb 'propose.' 'Propose + to + infinitive' is used when the subject is committing to perform the action. 'Propose + gerund' treats the action as a concept being put forward. 'Propose + noun phrase' offers a formal alternative — all three are valid in business proposal contexts.",category:"Grammar"},
  {id:"p5e2_159",question:"The assistant reminded everyone _____ bring their ID to the AGM.",options:["A) to","B) of","C) that","D) both A and C"],answer:"D",explanation:"'Both A and C' is correct because 'reminded everyone to bring their ID' (remind + object + to-infinitive, the most common structure) and 'reminded everyone that they should bring their ID' (remind + object + that-clause) are both grammatically correct and natural. 'Reminded everyone of' is also a valid structure ('reminded everyone of the need to bring ID'), but the specific completion 'of bring' without restructuring is ungrammatical, so option B alone does not work. The two accepted completions both naturally complete the sentence without additional restructuring.",category:"Grammar"},
  {id:"p5e2_160",question:"Management insisted _____ all costs be kept below $10,000.",options:["A) that","B) on","C) for","D) both A and B"],answer:"D",explanation:"'Both A and B' is correct because 'insisted that all costs be kept below $10,000' (using the subjunctive in a 'that-clause' after 'insist') and 'insisted on all costs being kept below $10,000' (using a gerund after the preposition 'on') are both grammatically correct formal English structures. 'Insisted for' is wrong because 'for' does not collocate with 'insist' in either a noun clause or a gerund structure in standard English. The two correct options demonstrate that 'insist' can take either a 'that-clause' (with subjunctive) or 'on + gerund' as its complement.",category:"Grammar"},
  {id:"p5e2_161",question:"The company _____ hiring decisions based on skills, not just qualifications.",options:["A) makes","B) takes","C) does","D) both A and B"],answer:"A",explanation:"'Makes' is correct because 'make decisions' is the standard and fixed collocation in English — decisions are always 'made,' and 'make hiring decisions' is the universally accepted business expression for taking staffing choices. 'Takes' is wrong because although 'take decisions' appears in some British English usage, it is a minority form and 'make decisions' is the standard collocation in all major varieties of business English; 'hiring decisions' specifically collocates with 'make.' 'Does' is wrong because 'do decisions' is not a grammatical collocation in English; 'do' does not collocate with 'decisions' in any standard construction. The fixed phrase is always 'make a decision' or 'make decisions,' and no other verb correctly fills this slot.",category:"Vocabulary"},
  {id:"p5e2_162",question:"She has _____ a strong reputation for delivering projects on time.",options:["A) built","B) built up","C) developed","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'built a reputation,' 'built up a reputation,' and 'developed a reputation' are all natural and widely used expressions for establishing a professional standing over time. 'Built a reputation' is the most direct and common collocation. 'Built up' adds a sense of gradual accumulation. 'Developed a reputation' emphasizes the growth and cultivation of a professional image — all three are correct.",category:"Vocabulary"},
  {id:"p5e2_163",question:"The supplier was _____ to deliver the components by the agreed date.",options:["A) unable","B) incapable","C) not capable","D) all of the above"],answer:"A",explanation:"'Unable' is correct because 'unable to + infinitive' is the standard structure expressing inability and fits directly before 'to deliver,' making 'unable to deliver' grammatically natural and idiomatic. 'Incapable' is wrong because 'incapable' requires the preposition 'of' followed by a gerund ('incapable of delivering'), not 'to + infinitive'; 'incapable to deliver' is ungrammatical in standard English. 'Not capable' is wrong for the same reason: 'capable' takes 'of + gerund' ('not capable of delivering'), not 'to + infinitive'; 'not capable to deliver' is non-standard. 'All of the above' is wrong because options B and C are ungrammatical in the sentence structure provided, so only option A correctly fills the blank.",category:"Vocabulary"},
  {id:"p5e2_164",question:"The manager _____ the team's efforts at the quarterly awards ceremony.",options:["A) acknowledged","B) recognized","C) appreciated","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'acknowledged,' 'recognized,' and 'appreciated' all describe a manager formally expressing gratitude or approval for the team's work at a ceremony. 'Acknowledged' means formally admitted or noted the team's contribution. 'Recognized' means to formally honor or reward the team's achievements. 'Appreciated' means to show that the efforts were valued — all three are appropriate in this ceremonial context.",category:"Vocabulary"},
  {id:"p5e2_165",question:"The data shows that customer _____ has improved by 12% this year.",options:["A) satisfy","B) satisfying","C) satisfaction","D) satisfied"],answer:"C",explanation:"'Satisfaction' is correct because a noun is needed to serve as the subject of the verb 'has improved,' and 'customer satisfaction' is the standard compound noun referring to the degree to which customers are pleased with a service or product. 'Satisfy' is wrong because it is a verb (e.g., 'to satisfy customers') and cannot function as the head noun of the subject noun phrase. 'Satisfying' is wrong because as a present participle or adjective it means giving satisfaction (e.g., 'a satisfying result'), and 'customer satisfying' is not a standard noun compound. 'Satisfied' is wrong because it is a past participle or adjective (e.g., 'satisfied customers') and does not form a standard noun compound in the subject position here.",category:"Word Form"},
  {id:"p5e2_166",question:"The company has a strict no-_____ policy in the workplace.",options:["A) discrimination","B) harassment","C) bullying","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'no-discrimination,' 'no-harassment,' and 'no-bullying' policies are all standard workplace policy terms describing what is prohibited in a professional environment. A 'no-discrimination policy' protects employees from unfair treatment based on protected characteristics. A 'no-harassment policy' specifically addresses unwanted behavior. A 'no-bullying policy' targets repeated aggressive behavior — all three are legitimate and common workplace policy descriptions.",category:"Vocabulary"},
  {id:"p5e2_167",question:"Please cc the finance team on all _____ relating to invoice payments.",options:["A) correspondence","B) emails","C) communications","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'correspondence,' 'emails,' and 'communications' relating to invoice payments are all types of written exchange that can be cc'd to the finance team. 'Correspondence' is the most formal term, encompassing all forms of written communication. 'Emails' is the most specific and common in modern business contexts. 'Communications' is the broadest term, covering all forms of exchange — all three are appropriate.",category:"Vocabulary"},
  {id:"p5e2_168",question:"I am writing _____ regard to your application submitted last week.",options:["A) in","B) with","C) regarding","D) both A and B"],answer:"D",explanation:"'Both A and B' is correct because 'in regard to' and 'with regard to' are both established formal English expressions meaning concerning or about something, and both are widely used in business correspondence. 'Regarding' is also correct English, but the blank precedes 'regard to,' so 'regarding' would make 'regarding regard to,' which is redundant and grammatically awkward. The two accepted options are the correct prepositions that complete the fixed formal phrases 'in regard to' and 'with regard to.'",category:"Preposition"},
  {id:"p5e2_169",question:"_____ order to meet the deadline, the team worked through the weekend.",options:["A) In","B) By","C) For","D) With"],answer:"A",explanation:"'In' is correct because 'in order to' is the fixed multi-word connector expressing purpose, meaning 'for the purpose of' or 'so as to,' and it requires the preposition 'in' before 'order to.' 'By order to' is not a standard English expression; 'by' introduces a method (e.g., 'by working through the weekend') not a purpose marker. 'For order to' is not a recognized English expression; 'for' introduces purpose in structures like 'for the purpose of,' not 'for order to.' 'With order to' is similarly not a standard English expression; none of the other prepositions form the fixed phrase 'in order to.'",category:"Connector"},
  {id:"p5e2_170",question:"The new system was implemented _____ the aim of reducing processing time.",options:["A) for","B) with","C) in","D) both A and B"],answer:"D",explanation:"'Both A and B' is correct because 'with the aim of' is the most common and natural fixed phrase expressing purpose in business English, and 'for the aim of' is also used, though less frequently — both convey that the system was implemented with the intention of reducing processing time. 'In the aim of' is not a standard English prepositional phrase; 'in' does not collocate with 'aim' in this structure. The two accepted options both correctly introduce the purpose, with 'with the aim of' being the strongly preferred form in formal writing.",category:"Preposition"},
  {id:"p5e2_171",question:"He _____ the project from start to finish without any assistance.",options:["A) handled","B) managed","C) oversaw","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'handled the project,' 'managed the project,' and 'oversaw the project' are all natural business English expressions describing taking responsibility for a project from beginning to end. 'Handled' suggests dealing with all aspects personally. 'Managed' emphasizes organization and control. 'Oversaw' suggests supervisory responsibility — all three are appropriate for describing independent project leadership.",category:"Vocabulary"},
  {id:"p5e2_172",question:"The company _____ on its clients' trust to sustain its business.",options:["A) relies","B) depends","C) counts","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'relies on,' 'depends on,' and 'counts on' are all synonymous phrasal verbs meaning to need something or someone for support or sustenance. 'Relies on' is the most formal of the three. 'Depends on' is neutral and widely used. 'Counts on' is slightly more informal but equally natural in this business context — all three correctly express dependence on clients' trust.",category:"Vocabulary"},
  {id:"p5e2_173",question:"The project is _____ schedule and within budget.",options:["A) on","B) in","C) at","D) by"],answer:"A",explanation:"'On' is correct because 'on schedule' is the fixed prepositional phrase meaning progressing as planned, without delays or early completion — it is the established collocation in project management language. 'In schedule' is wrong because 'in' does not collocate with 'schedule' in this meaning; 'in' is used with periods (e.g., 'in time') not with 'schedule.' 'At schedule' is wrong because 'at' indicates a specific point (e.g., 'at noon') and is not used to describe adherence to a project timeline. 'By schedule' is wrong because 'by' indicates a deadline or an agent in passive constructions, not conformity to a plan.",category:"Preposition"},
  {id:"p5e2_174",question:"The sales figures have been _____ steadily over the past six months.",options:["A) grow","B) grew","C) growing","D) grown"],answer:"C",explanation:"'Growing' is correct because 'have been + present participle' forms the present perfect continuous tense, used here to describe an ongoing trend that started in the past and continues into the present ('have been growing steadily'). 'Grow' is wrong because the base form cannot follow 'have been'; the present perfect continuous requires 'have been + -ing.' 'Grew' is wrong because it is the simple past tense and cannot complete the present perfect continuous structure. 'Grown' is wrong because while it is the past participle needed for the present perfect simple ('have grown'), the adverb 'steadily' and the phrase 'over the past six months' indicate an ongoing process, making the continuous form more appropriate.",category:"Grammar"},
  {id:"p5e2_175",question:"She _____ the report when her computer crashed and she lost all her work.",options:["A) writes","B) wrote","C) was writing","D) had written"],answer:"C",explanation:"'Was writing' is correct because the past continuous describes an action that was in progress at a specific past moment — writing the report was the ongoing background action that was interrupted by the computer crash. 'Writes' is wrong because the present simple describes current habits or general truths, not an interrupted past action. 'Wrote' is wrong because the simple past describes a completed action, but the context shows the writing was interrupted and therefore not completed. 'Had written' is wrong because the past perfect describes an action completed before another past action, but here the writing was still in progress when the crash occurred — it had not yet been completed.",category:"Grammar"},
  {id:"p5e2_176",question:"_____ the demand, the company hired 50 more customer service agents.",options:["A) Meeting","B) To meet","C) In meeting","D) both A and B"],answer:"D",explanation:"'Both A and B' is correct because 'to meet the demand' (an infinitive of purpose, meaning in order to meet it) and 'meeting the demand' (a participial phrase indicating the concurrent action or circumstance) are both grammatically valid ways to open the sentence. 'In meeting the demand' is wrong because 'in meeting' is not a standard grammatical construction for expressing purpose or cause in this type of sentence; it would require a different sentence structure. The two correct options each produce a natural sentence: 'to meet' emphasizes purpose, while 'meeting' emphasizes the circumstance.",category:"Grammar"},
  {id:"p5e2_177",question:"All staff are _____ to report any safety hazards immediately.",options:["A) urged","B) encouraged","C) requested","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'urged to report,' 'encouraged to report,' and 'requested to report' are all grammatically correct and contextually appropriate passive structures conveying that staff are expected to take action on safety hazards. 'Urged' implies strong encouragement with a sense of urgency. 'Encouraged' suggests positive motivation. 'Requested' is more formal and polite — all three naturally precede 'to report' and convey the safety message effectively.",category:"Vocabulary"},
  {id:"p5e2_178",question:"The CEO _____ a visit to the Singapore branch next month.",options:["A) is planning","B) plans","C) has planned","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'is planning a visit' (present continuous for a future arrangement), 'plans a visit' (present simple for a scheduled future event), and 'has planned a visit' (present perfect for a decision already made) are all grammatically valid and natural ways to express the CEO's upcoming visit. Each tense offers a slightly different nuance about the stage of planning, but all three are used in standard business English to describe future plans.",category:"Grammar"},
  {id:"p5e2_179",question:"The contract was signed in the _____ of two witnesses.",options:["A) presence","B) present","C) attendance","D) both A and C"],answer:"A",explanation:"'Presence' is correct because 'in the presence of witnesses' is the standard fixed legal and formal expression describing a witnessed signing, meaning the witnesses were physically there when the contract was signed. 'Present' is wrong because while 'present' as an adjective means being there, 'in the present of' is not a grammatical noun phrase; the noun 'presence' is required. 'Attendance' is wrong because 'in the attendance of witnesses' is not a standard legal or business expression; while witnesses may be 'in attendance,' the fixed legal phrase is always 'in the presence of,' not 'in the attendance of.' 'Both A and C' is wrong because option C ('attendance') does not form an established legal expression in this structure, making only A correct.",category:"Vocabulary"},
  {id:"p5e2_180",question:"The company offers _____ compensation for employees who work on public holidays.",options:["A) additional","B) extra","C) supplemental","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'additional compensation,' 'extra compensation,' and 'supplemental compensation' are all natural business expressions meaning pay that is on top of the regular salary for working on public holidays. 'Additional' is formal and widely used in HR policy language. 'Extra' is the most colloquial and common everyday term. 'Supplemental' is the most formal and specific, often used in legal or policy documents — all three correctly describe the nature of the holiday pay.",category:"Vocabulary"},
  {id:"p5e2_181",question:"_____ the time the investigation concluded, the suspect had already left the country.",options:["A) By","B) Until","C) When","D) After"],answer:"A",explanation:"'By' is correct because 'by the time + clause' indicates that one action was completed before or at the same moment as another past reference point, and the past perfect 'had already left' confirms the earlier completion. 'Until' is wrong because 'until the time the investigation concluded' would mean the suspect stayed in the country up to that point, which is the opposite of what the sentence says. 'When' is wrong because 'when the investigation concluded' would suggest the two actions occurred at the same time, but the past perfect shows the leaving happened before the conclusion. 'After' is wrong because 'after the time the investigation concluded' would mean the suspect left following the investigation's end, contradicting the past perfect tense used.",category:"Grammar"},
  {id:"p5e2_182",question:"The marketing budget for next year has been _____ slightly.",options:["A) increase","B) increasing","C) increased","D) increment"],answer:"C",explanation:"'Increased' is correct because 'has been + past participle' forms the present perfect passive, meaning a decision to raise the budget was recently made, and 'increased' is the required past participle. 'Increase' is wrong because the base form cannot complete the passive perfect; the past participle 'increased' is required after 'has been.' 'Increasing' is wrong because the present participle after 'has been' would form the present perfect continuous active ('has been increasing'), which changes the voice and meaning. 'Increment' is wrong because it is a noun meaning a small increase, not a verb form that can complete the passive perfect structure.",category:"Grammar"},
  {id:"p5e2_183",question:"We aim to _____ the issue before the client's next visit.",options:["A) solve","B) resolve","C) fix","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'solve the issue,' 'resolve the issue,' and 'fix the issue' are all natural business English expressions meaning to find a solution and eliminate the problem before the client visits. 'Solve' is commonly used for problems requiring analysis and a solution. 'Resolve' is often used for disputes, conflicts, or technical issues. 'Fix' is more informal and direct, especially for technical or operational problems — all three are valid.",category:"Vocabulary"},
  {id:"p5e2_184",question:"The company will donate 5% of its _____ profits to charity.",options:["A) annual","B) yearly","C) year's","D) both A and B"],answer:"D",explanation:"'Both A and B' is correct because 'annual profits' and 'yearly profits' are synonymous adjectives meaning profits calculated over a one-year period, and both are equally correct and widely used in business and financial contexts. 'Year's profits' is wrong because while the possessive noun form is grammatically possible in some contexts, 'year's profits' is less standard than the adjective forms 'annual' or 'yearly' in formal financial reporting and policy statements. 'Annual' is the more formal and common term in financial reporting, while 'yearly' is slightly more general — both adjective forms are the preferred and accepted choices here.",category:"Vocabulary"},
  {id:"p5e2_185",question:"Employees may park in the visitor lot _____ the main lot is full.",options:["A) when","B) if","C) in case","D) both A and B"],answer:"D",explanation:"'Both A and B' is correct because 'when the main lot is full' (implying it regularly fills up, making this a known recurring situation) and 'if the main lot is full' (treating it as a conditional possibility) are both grammatically correct and contextually appropriate. 'In case' is wrong because 'in case the lot is full' means as a precaution against the possibility of it being full — this implies parking in the visitor lot in advance as a preventive measure, which changes the meaning from a direct permission triggered by the lot being full. The two accepted options both describe the trigger condition for using the visitor lot.",category:"Grammar"},
  {id:"p5e2_186",question:"The board has approved the plan _____ it is implemented by year-end.",options:["A) provided","B) providing","C) on condition","D) both A and B"],answer:"D",explanation:"'Both A and B' is correct because 'provided it is implemented' and 'providing it is implemented' are both standard conditional conjunctions in formal English, both meaning 'on the condition that' or 'as long as.' 'On condition' is not complete on its own in this blank — 'on condition that' would be correct, but 'on condition it is implemented' (without 'that') is less standard than 'provided/providing.' The two correct options are synonymous conditional conjunctions widely accepted in business and legal English.",category:"Grammar"},
  {id:"p5e2_187",question:"The new product will be available _____ order from our website.",options:["A) to","B) for","C) on","D) by"],answer:"C",explanation:"'On' is correct because 'available on order' is a fixed business phrase meaning the product is not in stock but can be obtained by placing an order, and it is the standard expression in retail and e-commerce contexts. 'To' is wrong because while 'available to order' appears in some British English contexts, 'on order' is the established and more widely recognized collocation in formal business and retail language. 'For' is wrong because 'available for order' is not the standard collocation in English; 'for' introduces purpose rather than the means of obtaining the product. 'By' is wrong because 'available by order' is not a recognized standard expression in English commerce.",category:"Preposition"},
  {id:"p5e2_188",question:"The team leader sent the document _____ all members for review.",options:["A) to","B) for","C) at","D) toward"],answer:"A",explanation:"'To' is correct because 'send something to someone' is the standard ditransitive structure where 'to' introduces the indirect object — the recipients of the document. 'For' is wrong because 'sent the document for all members' would imply the document was sent on behalf of the members or for their benefit in a different sense, rather than to them as recipients. 'At' is wrong because 'at' indicates direction toward a target or a point in space or time, not the recipient of a transmitted document. 'Toward' is wrong because it expresses direction of movement rather than specifying the recipient of something that is formally transmitted.",category:"Preposition"},
  {id:"p5e2_189",question:"We will _____ the final decision after consulting with all stakeholders.",options:["A) announce","B) make","C) reach","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'announce the final decision,' 'make the final decision,' and 'reach the final decision' are all grammatically correct and natural collocations in business English. 'Announce the decision' means to communicate it publicly. 'Make the decision' means to decide. 'Reach the decision' emphasizes the process of coming to a conclusion through discussion — all three are valid depending on the intended emphasis.",category:"Vocabulary"},
  {id:"p5e2_190",question:"The manager _____ the team to achieve even better results next quarter.",options:["A) motivated","B) inspired","C) encouraged","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'motivated,' 'inspired,' and 'encouraged' the team are all valid and natural expressions describing a manager who elevated the team's morale and drive. 'Motivated' implies providing reasons or incentives to perform. 'Inspired' suggests creating enthusiasm and a desire to excel. 'Encouraged' means to give support and confidence — all three naturally take the object 'the team' and the infinitive 'to achieve.'",category:"Vocabulary"},
  {id:"p5e2_191",question:"Could you _____ me how to access the shared drive?",options:["A) show","B) teach","C) demonstrate","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'show me how to access,' 'teach me how to access,' and 'demonstrate to me how to access' (or 'demonstrate how to access') are all natural ways to ask someone to explain or illustrate how to use the shared drive. 'Show' implies a practical demonstration. 'Teach' implies instruction and learning. 'Demonstrate' implies a formal or thorough showing of a process — all three are appropriate in this context.",category:"Vocabulary"},
  {id:"p5e2_192",question:"The client _____ the invoice within two days of receiving it.",options:["A) settled","B) paid","C) cleared","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'settled the invoice,' 'paid the invoice,' and 'cleared the invoice' are all standard business English expressions for discharging a financial obligation promptly. 'Settled' is formal and often used in financial and legal contexts for final payment. 'Paid' is the most general and widely understood term. 'Cleared' is used in banking and finance to indicate that a payment has been processed and completed — all three are valid.",category:"Vocabulary"},
  {id:"p5e2_193",question:"Please keep this information _____ until the official announcement.",options:["A) confidential","B) private","C) secret","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'keep it confidential,' 'keep it private,' and 'keep it secret' all express the same instruction not to share information before the official announcement. 'Confidential' is the most formal and commonly used in business and legal settings for restricted information. 'Private' means not for public knowledge. 'Secret' means concealed from general knowledge — all three function as predicate adjectives after 'keep this information ___.'",category:"Vocabulary"},
  {id:"p5e2_194",question:"The report was _____ by the senior editor before publication.",options:["A) approved","B) endorsed","C) cleared","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'approved by,' 'endorsed by,' and 'cleared by' the senior editor all describe the act of giving formal authorization for the report to be published. 'Approved' means officially accepted or agreed to. 'Endorsed' means formally supported or authorized, often with the implication of public backing. 'Cleared' means given permission to proceed, often after a review — all three are appropriate passive constructions here.",category:"Vocabulary"},
  {id:"p5e2_195",question:"The seminar covers the _____ skills needed for effective leadership.",options:["A) core","B) key","C) essential","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'core skills,' 'key skills,' and 'essential skills' are all common and interchangeable business English expressions describing the most important abilities required for a purpose. 'Core' emphasizes fundamental or central skills. 'Key' emphasizes the most important or critical ones. 'Essential' means absolutely necessary — all three naturally precede 'skills needed for effective leadership.'",category:"Vocabulary"},
  {id:"p5e2_196",question:"She was _____ for her contributions to the company over 20 years.",options:["A) honored","B) recognized","C) awarded","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'honored for her contributions,' 'recognized for her contributions,' and 'awarded for her contributions' are all grammatically correct and contextually natural ways to describe formal acknowledgment of long service. 'Honored' suggests a mark of respect and distinction. 'Recognized' implies formal acknowledgment of achievement. 'Awarded' implies receiving a specific prize or commendation — all three are appropriate for a 20-year contribution ceremony.",category:"Vocabulary"},
  {id:"p5e2_197",question:"The manager had a _____ word with the employee after the incident.",options:["A) brief","B) quick","C) short","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'a brief word,' 'a quick word,' and 'a short word' are all established English idioms meaning a brief, informal conversation, often used in workplace settings for a private discussion between a manager and employee. 'Brief word' is slightly more formal. 'Quick word' is the most colloquial and widely used. 'Short word' is less common but equally valid — all three are natural in this context.",category:"Vocabulary"},
  {id:"p5e2_198",question:"We hope to _____ an agreement by the end of the current quarter.",options:["A) reach","B) conclude","C) finalize","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'reach an agreement,' 'conclude an agreement,' and 'finalize an agreement' are all standard business English collocations for completing a negotiation successfully. 'Reach an agreement' means to come to a mutual decision after discussion. 'Conclude an agreement' is more formal and implies the official closing of negotiations. 'Finalize an agreement' means to complete the last details and formally seal the deal — all three are appropriate.",category:"Vocabulary"},
  {id:"p5e2_199",question:"The company _____ a team to investigate the cause of the data loss.",options:["A) assembled","B) formed","C) put together","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'assembled a team,' 'formed a team,' and 'put together a team' are all natural business English expressions describing the act of bringing people together into a working group for a specific purpose. 'Assembled' suggests gathering people from different places or departments. 'Formed' implies officially establishing the team. 'Put together' is more informal and emphasizes the practical act of combining people with the right skills — all three are valid.",category:"Vocabulary"},
  {id:"p5e2_200",question:"The new cafeteria will _____ a wide variety of meals for all dietary needs.",options:["A) offer","B) provide","C) serve","D) all of the above"],answer:"D",explanation:"'All of the above' is correct because 'offer a wide variety of meals,' 'provide a wide variety of meals,' and 'serve a wide variety of meals' are all natural and correct expressions for a cafeteria making food available. 'Offer' emphasizes the availability and choice given to customers. 'Provide' emphasizes supplying meals as a service. 'Serve' is the most specific to food service, referring to the physical act of presenting meals — all three are appropriate for describing a cafeteria's function.",category:"Vocabulary"}
];
